head.b:skin:
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --bg:#05050a;--sur:#0d0d15;--sur2:#14141e;
  --acc:#7c3aed;--acc2:#a855f7;--pink:#ec4899;--cyan:#22d3ee;
  --glow:rgba(124,58,237,.4);
  --txt:#eeeeff;--dim:#6666aa;
  --glass:rgba(255,255,255,.04);--bdr:rgba(255,255,255,.07);
}
html{scroll-behavior:smooth;-webkit-text-size-adjust:100%;-webkit-tap-highlight-color:transparent}
body{background:var(--bg);color:var(--txt);font-family:'Nunito',sans-serif;min-height:100vh;overflow-x:hidden;-webkit-font-smoothing:antialiased}
a{color:inherit;text-decoration:none}
button{font-family:'Nunito',sans-serif;touch-action:manipulation}
img{max-width:100%;display:block}

#loader{position:fixed;inset:0;background:var(--bg);display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:9999;transition:opacity .08s,visibility .08s}
#loader.off{opacity:0;visibility:hidden;pointer-events:none}
@keyframes loader-auto-hide{0%,30%{opacity:1;visibility:visible}100%{opacity:0;visibility:hidden;pointer-events:none}}
#loader{animation:loader-auto-hide 1.2s ease forwards}
.ld-logo{font-family:'Rajdhani',sans-serif;font-size:36px;font-weight:700;letter-spacing:3px}
.ld-logo b{color:var(--acc2)}
.ld-track{width:130px;height:3px;background:var(--sur2);border-radius:9px;margin-top:16px;overflow:hidden}
.ld-fill{height:100%;width:0;background:linear-gradient(90deg,var(--acc),var(--pink));border-radius:9px;animation:ldfill 1.4s ease forwards}
@keyframes ldfill{to{width:100%}}

#pbar{position:fixed;top:0;left:0;height:3px;width:0;background:linear-gradient(90deg,var(--acc),var(--pink),var(--cyan));z-index:9999;box-shadow:0 0 10px var(--glow);transition:width .25s,opacity .4s;pointer-events:none}
#pbar.done{width:100%!important;opacity:0}

#hdr{position:fixed;top:0;left:0;right:0;height:56px;background:rgba(5,5,10,.94);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);border-bottom:1px solid var(--bdr);display:flex;align-items:center;padding:0 4%;gap:8px;z-index:1000}
#hdr.hidden{display:none!important}
#hdr.hidden~#app,body:has(#hdr.hidden) #app{padding-top:0!important}
.logo{font-family:'Rajdhani',sans-serif;font-size:22px;font-weight:700;letter-spacing:2px;cursor:pointer;flex-shrink:0;user-select:none;color:var(--txt)}
.logo b{color:var(--acc2)}
.hnav{display:flex;gap:2px;flex-shrink:0}
.hn{background:none;border:none;color:var(--dim);font:700 13px/1 'Nunito',sans-serif;padding:7px 11px;border-radius:7px;cursor:pointer;transition:all .18s;white-space:nowrap;touch-action:manipulation}
.hn:hover,.hn.on{background:var(--glass);color:var(--txt)}
.hn.on{color:var(--acc2)}
#mob-btn{display:none;background:none;border:none;color:var(--txt);cursor:pointer;padding:6px;flex-shrink:0;touch-action:manipulation}
#mob-drawer{display:none;position:fixed;top:56px;left:0;right:0;background:rgba(5,5,10,.98);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);border-bottom:1px solid var(--bdr);z-index:999;flex-direction:column;padding:6px 4% 10px}
#mob-drawer.open{display:flex}
#mob-drawer .hn{padding:12px 14px;font-size:14px;border-radius:8px}
#rand-btn{background:none;border:none;color:var(--dim);cursor:pointer;padding:6px 9px;display:flex;align-items:center;gap:5px;font:700 12px 'Nunito',sans-serif;border-radius:7px;transition:all .18s;touch-action:manipulation;flex-shrink:0;white-space:nowrap}
#rand-btn:hover{background:var(--glass);color:var(--acc2)}
.sw{flex:1;max-width:340px;min-width:0;display:flex;align-items:center;background:var(--glass);border:1px solid var(--bdr);border-radius:9px;overflow:hidden;transition:border-color .2s}
.sw:focus-within{border-color:var(--acc)}
#si{flex:1;background:none;border:none;outline:none;color:var(--txt);font:600 13px 'Nunito',sans-serif;padding:10px 12px;min-width:0;-webkit-appearance:none}
#si::placeholder{color:var(--dim)}
#asearch-btn{background:none;border:none;color:var(--dim);padding:10px 8px;cursor:pointer;flex-shrink:0;display:flex;align-items:center;transition:color .18s;touch-action:manipulation}
#asearch-btn:hover,#asearch-btn.on{color:var(--acc2)}
#sb{background:none;border:none;color:var(--acc2);padding:10px 12px;cursor:pointer;flex-shrink:0;display:flex;align-items:center;touch-action:manipulation}
#pwa-btn{display:none;align-items:center;gap:5px;background:var(--glass);border:1px solid var(--bdr);color:var(--dim);font:700 11px 'Nunito',sans-serif;padding:6px 11px;border-radius:7px;cursor:pointer;flex-shrink:0;touch-action:manipulation;white-space:nowrap;transition:all .18s}
#pwa-btn:hover{border-color:var(--acc);color:var(--acc2)}

#app{padding-top:56px;min-height:calc(100vh - 56px);transition:opacity .15s}
#app.fade{opacity:0;pointer-events:none}

/* Advanced search panel */
#asearch-panel{display:none;position:fixed;top:56px;left:0;right:0;background:rgba(5,5,10,.98);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);border-bottom:1px solid var(--bdr);z-index:998;padding:14px 4%}
#asearch-panel.open{display:block}
.asp-row{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px}
.asp-group{display:flex;flex-direction:column;gap:4px}
.asp-label{font-size:10px;color:var(--dim);font-weight:800;letter-spacing:.8px;text-transform:uppercase}
.asp-sel{background:var(--sur2);border:1px solid var(--bdr);color:var(--txt);font:600 12px 'Nunito',sans-serif;padding:7px 10px;border-radius:7px;outline:none;cursor:pointer;-webkit-appearance:none;appearance:none;min-width:110px}
.asp-sel:focus{border-color:var(--acc)}
.asp-btns{display:flex;gap:8px;align-items:center}

/* Toast */
#toast-wrap{position:fixed;bottom:76px;left:50%;transform:translateX(-50%);z-index:9998;display:flex;flex-direction:column;gap:8px;align-items:center;pointer-events:none}
.toast{background:var(--sur2);border:1px solid var(--bdr);color:var(--txt);font-size:12px;font-weight:700;padding:9px 18px;border-radius:8px;box-shadow:0 4px 18px rgba(0,0,0,.5);animation:toast-in .3s ease;pointer-events:none;white-space:nowrap}
.toast.out{animation:toast-out .3s ease forwards}
@keyframes toast-in{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
@keyframes toast-out{to{opacity:0;transform:translateY(8px)}}

/* Skeleton shimmer */
.card-skel{position:relative;border-radius:9px;aspect-ratio:2/3;background:var(--sur2);border:1px solid var(--bdr);overflow:hidden}
.card-skel::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);animation:shimmer 1.5s infinite;transform:translateX(-100%)}
@keyframes shimmer{to{transform:translateX(100%)}}

/* Hero */
.hero{position:relative;height:420px;overflow:hidden;margin-bottom:24px}
.hero-bg{position:absolute;inset:0;background-size:cover;background-position:center 20%;filter:blur(4px) brightness(.38);transform:scale(1.07);transition:background-image .6s}
.hero-grad{position:absolute;inset:0;background:linear-gradient(90deg,rgba(5,5,10,.97) 25%,rgba(5,5,10,.3) 70%),linear-gradient(0deg,var(--bg) 0%,transparent 32%)}
.hero-cnt{position:relative;z-index:2;height:100%;display:flex;flex-direction:column;justify-content:center;padding:0 5%;max-width:520px}
.hero-badge{display:inline-flex;align-items:center;background:var(--acc);color:#fff;font-size:10px;font-weight:800;padding:4px 10px;border-radius:4px;letter-spacing:1.5px;text-transform:uppercase;margin-bottom:10px;width:fit-content}
.hero-title{font-family:'Rajdhani',sans-serif;font-size:clamp(22px,4.5vw,42px);font-weight:700;line-height:1.1;color:#fff;margin-bottom:9px}
.hero-desc{font-size:13px;color:#aaa;line-height:1.6;margin-bottom:18px;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;overflow:hidden}
.hero-btns{display:flex;gap:8px;flex-wrap:wrap}

.bp{display:inline-flex;align-items:center;gap:6px;background:linear-gradient(135deg,var(--acc),var(--acc2));color:#fff;border:none;font:800 13px 'Nunito',sans-serif;padding:10px 20px;border-radius:8px;cursor:pointer;box-shadow:0 5px 18px var(--glow);transition:transform .2s,box-shadow .2s;white-space:nowrap;touch-action:manipulation}
.bp:hover{transform:translateY(-2px);box-shadow:0 8px 26px var(--glow)}
.bp:active{transform:scale(.96)}
.bs{display:inline-flex;align-items:center;gap:6px;background:var(--glass);color:var(--txt);border:1px solid var(--bdr);font:700 13px 'Nunito',sans-serif;padding:10px 20px;border-radius:8px;cursor:pointer;transition:background .2s;white-space:nowrap;touch-action:manipulation}
.bs:hover{background:rgba(255,255,255,.08)}
.bs:active{transform:scale(.96)}

.sec{padding:0 4% 28px}
.sec-hdr{display:flex;align-items:center;justify-content:space-between;margin-bottom:14px}
.sec-title{font-family:'Rajdhani',sans-serif;font-size:19px;font-weight:700;display:flex;align-items:center;gap:8px}
.sec-title::before{content:'';width:4px;height:18px;background:linear-gradient(180deg,var(--acc),var(--pink));border-radius:99px;display:inline-block;flex-shrink:0}
.sec-all{background:none;border:none;color:var(--acc2);font:700 12px 'Nunito',sans-serif;cursor:pointer;touch-action:manipulation}
.sec-all:hover{color:var(--pink)}

.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(145px,1fr));gap:12px}

/* Genre filter row */
.genre-row{display:flex;gap:6px;overflow-x:auto;padding:0 0 12px;-webkit-overflow-scrolling:touch;scrollbar-width:none}
.genre-row::-webkit-scrollbar{display:none}
.gbtn{background:var(--glass);border:1px solid var(--bdr);color:var(--dim);font:700 11px 'Nunito',sans-serif;padding:5px 13px;border-radius:20px;cursor:pointer;white-space:nowrap;transition:all .18s;flex-shrink:0;touch-action:manipulation}
.gbtn:hover,.gbtn.on{background:rgba(124,58,237,.18);border-color:var(--acc);color:var(--acc2)}

/* Card */
.card{position:relative;border-radius:9px;overflow:hidden;aspect-ratio:2/3;background:var(--sur);border:1px solid var(--bdr);cursor:pointer;transition:transform .26s,border-color .26s,box-shadow .26s;opacity:0;transform:translateY(10px)}
.card.in{animation:cin .4s ease forwards}
@keyframes cin{to{opacity:1;transform:translateY(0)}}
.card:hover{transform:translateY(-5px) scale(1.03);border-color:var(--acc);box-shadow:0 10px 30px rgba(124,58,237,.4)}
.card:active{transform:scale(.96)}
.card img{width:100%;height:100%;object-fit:cover;display:block;transition:transform .4s}
.card:hover img{transform:scale(1.06)}
.cbadge{position:absolute;top:7px;font-size:9px;font-weight:800;padding:3px 7px;border-radius:4px;letter-spacing:.8px;text-transform:uppercase;z-index:3}
.cbadge.l{left:7px;background:rgba(0,0,0,.72);color:#fff;border:1px solid var(--bdr)}
.cbadge.r{right:7px;background:rgba(0,0,0,.75);color:#fbbf24}
.heart-btn{position:absolute;top:34px;right:7px;width:26px;height:26px;background:rgba(0,0,0,.72);border:1px solid var(--bdr);border-radius:50%;display:flex;align-items:center;justify-content:center;cursor:pointer;z-index:4;transition:all .2s;touch-action:manipulation;opacity:0}
.card:hover .heart-btn,.heart-btn.on{opacity:1}
.heart-btn:hover{background:rgba(0,0,0,.9);transform:scale(1.15)}
.heart-btn.on{background:rgba(236,72,153,.18);border-color:rgba(236,72,153,.4)}
.heart-btn svg{transition:all .2s}
@media(hover:none){.heart-btn{opacity:1}}
.cov{position:absolute;bottom:0;left:0;right:0;background:linear-gradient(transparent,rgba(0,0,0,.55) 38%,rgba(0,0,0,.97));padding:44px 8px 10px;opacity:0;transition:opacity .26s;display:flex;flex-direction:column;align-items:center;gap:6px;z-index:3}
.card:hover .cov{opacity:1}
.ctitle{font-size:11px;font-weight:800;color:#fff;text-transform:uppercase;letter-spacing:.4px;text-align:center;width:100%;padding:0 4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.cwbtn{display:inline-flex;align-items:center;gap:4px;background:linear-gradient(135deg,var(--acc),var(--acc2));color:#fff;font-size:10px;font-weight:800;padding:4px 11px;border-radius:5px;border:none;pointer-events:none}

/* Horizontal scroll sections */
.hscroll-outer{overflow-x:auto;-webkit-overflow-scrolling:touch;scrollbar-width:none;margin:0 -4%;padding:0 4% 4px}
.hscroll-outer::-webkit-scrollbar{display:none}
.hscroll{display:flex;gap:10px;width:max-content}
.hcard{flex-shrink:0;width:108px;cursor:pointer;border-radius:8px;overflow:hidden;background:var(--sur2);border:1px solid var(--bdr);transition:transform .2s,border-color .2s;touch-action:manipulation}
.hcard:hover{transform:translateY(-3px);border-color:var(--acc)}
.hcard img{width:108px;height:152px;object-fit:cover;display:block}
.hcard-info{padding:5px 6px}
.hcard-title{font-size:10px;font-weight:800;color:var(--txt);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.hcard-sub{font-size:9px;color:var(--dim);margin-top:2px}

/* Character / Staff cards */
.char-grid{display:flex;gap:10px;overflow-x:auto;-webkit-overflow-scrolling:touch;scrollbar-width:none;padding-bottom:6px}
.char-grid::-webkit-scrollbar{display:none}
.char-card{flex-shrink:0;width:90px;text-align:center}
.char-card img{width:90px;height:90px;object-fit:cover;border-radius:50%;border:2px solid var(--bdr);display:block;margin:0 auto 6px;transition:border-color .2s}
.char-card:hover img{border-color:var(--acc2)}
.char-name{font-size:10px;font-weight:800;color:var(--txt);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;padding:0 2px}
.char-role{font-size:9px;color:var(--dim);margin-top:2px}

/* VA card (side by side) */
.va-row{display:flex;flex-direction:column;gap:8px}
.va-item{display:flex;align-items:center;gap:10px;background:var(--sur2);border:1px solid var(--bdr);border-radius:8px;padding:8px 10px;overflow:hidden}
.va-item img{width:44px;height:44px;object-fit:cover;border-radius:50%;flex-shrink:0;border:1px solid var(--bdr)}
.va-info{flex:1;min-width:0}
.va-name{font-size:12px;font-weight:800;color:var(--txt);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.va-sub{font-size:10px;color:var(--dim);margin-top:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.va-role{font-size:9px;background:rgba(124,58,237,.18);border:1px solid rgba(124,58,237,.28);color:var(--acc2);border-radius:4px;padding:2px 7px;font-weight:800;flex-shrink:0;white-space:nowrap}

/* Studio tag */
.studio-tag{display:inline-flex;align-items:center;background:rgba(34,211,238,.08);border:1px solid rgba(34,211,238,.22);color:var(--cyan);border-radius:20px;padding:5px 14px;font-size:11px;font-weight:800;cursor:pointer;transition:background .18s;margin:3px}
.studio-tag:hover{background:rgba(34,211,238,.18)}

/* Trailer embed */
.trailer-wrap{position:relative;width:100%;max-width:540px;aspect-ratio:16/9;border-radius:10px;overflow:hidden;background:#000;border:1px solid var(--bdr)}
.trailer-wrap iframe{width:100%;height:100%;border:none}

/* Relations */
.rel-grid{display:flex;gap:10px;flex-wrap:wrap}
.rel-card{display:flex;align-items:center;gap:9px;background:var(--sur2);border:1px solid var(--bdr);border-radius:8px;padding:7px 10px;cursor:pointer;transition:border-color .2s;max-width:220px;overflow:hidden}
.rel-card:hover{border-color:var(--acc)}
.rel-card img{width:36px;height:50px;object-fit:cover;border-radius:4px;flex-shrink:0}
.rel-info{min-width:0}
.rel-type{font-size:9px;color:var(--acc2);font-weight:800;letter-spacing:.6px;text-transform:uppercase;margin-bottom:2px}
.rel-title{font-size:11px;font-weight:800;color:var(--txt);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}

/* Stats bar */
.stats-grid{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:18px}
.stat-box{background:var(--sur2);border:1px solid var(--bdr);border-radius:8px;padding:10px 16px;min-width:90px;text-align:center}
.stat-val{font-family:'Rajdhani',sans-serif;font-size:20px;font-weight:700;color:var(--acc2)}
.stat-lbl{font-size:10px;color:var(--dim);font-weight:700;margin-top:2px;text-transform:uppercase;letter-spacing:.6px}

.ep-badge{position:absolute;top:5px;left:5px;background:linear-gradient(135deg,var(--acc),var(--acc2));color:#fff;font-size:9px;font-weight:800;padding:2px 7px;border-radius:4px;letter-spacing:.5px;z-index:2}
.hcard{position:relative}

.countdown-box{background:linear-gradient(135deg,rgba(124,58,237,.15),rgba(168,85,247,.1));border:1px solid rgba(124,58,237,.35);border-radius:10px;padding:14px 18px;margin-bottom:20px;display:flex;align-items:center;gap:14px;flex-wrap:wrap}
.countdown-icon{width:36px;height:36px;background:linear-gradient(135deg,var(--acc),var(--acc2));border-radius:50%;display:flex;align-items:center;justify-content:center;flex-shrink:0}
.countdown-label{font-size:11px;color:var(--acc2);font-weight:800;letter-spacing:.8px;text-transform:uppercase;margin-bottom:3px}
.countdown-ep{font-size:13px;color:var(--txt);font-weight:700;margin-bottom:6px}
.countdown-timer{display:flex;gap:8px;align-items:center}
.cd-unit{text-align:center;min-width:42px}
.cd-val{font-family:'Rajdhani',sans-serif;font-size:22px;font-weight:700;color:var(--acc2);line-height:1;display:block}
.cd-lbl{font-size:9px;color:var(--dim);font-weight:800;letter-spacing:.8px;text-transform:uppercase;margin-top:2px}
.cd-sep{font-family:'Rajdhani',sans-serif;font-size:20px;color:var(--acc);font-weight:700;margin-bottom:6px}
.browse-page{padding:0 4px}
.browse-section-label{font-size:10px;font-weight:800;letter-spacing:1px;text-transform:uppercase;color:var(--dim);margin-bottom:8px}
.browse-pills{display:flex;flex-wrap:wrap;gap:6px}
.br-pill{background:var(--glass);border:1px solid var(--bdr);color:var(--dim);font-size:12px;font-weight:700;padding:5px 13px;border-radius:20px;cursor:pointer;transition:all .15s;white-space:nowrap}
.br-pill:hover{border-color:var(--acc);color:var(--txt)}
.br-pill.active{background:linear-gradient(135deg,var(--acc),var(--acc2));border-color:transparent;color:#fff}

.about-page{max-width:860px;margin:0 auto;padding:0 4% 40px}
.about-hero{position:relative;border-radius:14px;overflow:hidden;margin-bottom:32px;padding:48px 36px;background:linear-gradient(135deg,rgba(124,58,237,.18),rgba(168,85,247,.08));border:1px solid rgba(124,58,237,.25)}
.about-hero-bg{position:absolute;inset:0;background:radial-gradient(ellipse at 20% 50%,rgba(124,58,237,.15) 0%,transparent 70%),radial-gradient(ellipse at 80% 20%,rgba(236,72,153,.1) 0%,transparent 60%);pointer-events:none}
.about-hero-cnt{position:relative;z-index:1}
.about-logo{font-family:'Rajdhani',sans-serif;font-size:38px;font-weight:700;color:#fff;margin-bottom:10px;letter-spacing:-1px}
.about-logo b{color:var(--acc2)}
.about-tagline{font-size:15px;color:#bbb;line-height:1.6;margin-bottom:20px;max-width:520px}
.about-section{margin-bottom:32px}
.about-h2{font-family:'Rajdhani',sans-serif;font-size:22px;font-weight:700;color:var(--txt);margin-bottom:14px;display:flex;align-items:center;gap:8px}
.about-h2::before{content:'';width:4px;height:20px;background:linear-gradient(180deg,var(--acc),var(--pink));border-radius:99px;flex-shrink:0}
.about-p{font-size:14px;color:#aaa;line-height:1.75;margin-bottom:12px}
.about-features{display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:14px}
.about-feat{display:flex;gap:12px;align-items:flex-start;background:var(--sur2);border:1px solid var(--bdr);border-radius:10px;padding:16px;transition:border-color .2s}
.about-feat:hover{border-color:rgba(124,58,237,.4)}
.about-feat-ic{width:40px;height:40px;border-radius:8px;background:linear-gradient(135deg,rgba(124,58,237,.2),rgba(168,85,247,.1));display:flex;align-items:center;justify-content:center;flex-shrink:0;color:var(--acc2)}
.about-feat-title{font-size:13px;font-weight:800;color:var(--txt);margin-bottom:4px}
.about-feat-desc{font-size:12px;color:var(--dim);line-height:1.5}
.about-faq{display:flex;flex-direction:column;gap:8px}
.faq-item{background:var(--sur2);border:1px solid var(--bdr);border-radius:10px;overflow:hidden;transition:border-color .2s}
.faq-item.open{border-color:rgba(124,58,237,.4)}
.faq-q{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:14px 16px;cursor:pointer;font-size:14px;font-weight:700;color:var(--txt)}
.faq-arr{flex-shrink:0;transition:transform .25s;color:var(--dim)}
.faq-item.open .faq-arr{transform:rotate(180deg);color:var(--acc2)}
.faq-a{max-height:0;overflow:hidden;transition:max-height .3s ease,padding .3s;font-size:13px;color:#aaa;line-height:1.7;padding:0 16px}
.faq-item.open .faq-a{max-height:200px;padding:0 16px 14px}
.about-disclaimer{background:rgba(251,191,36,.06);border:1px solid rgba(251,191,36,.18);border-radius:10px;padding:14px 18px}
.about-disclaimer p{font-size:12px;color:#aaa;line-height:1.6;margin:0}
.lnd-wrap{min-height:100vh;background:var(--bg);display:flex;flex-direction:column}
.lnd-nav{display:flex;align-items:center;justify-content:center;gap:6px;padding:16px 4%;border-bottom:1px solid var(--bdr);flex-wrap:wrap;background:var(--bg);position:relative;z-index:10}
.lnd-nl{background:none;border:none;color:var(--dim);font:600 13px/1 "Nunito",sans-serif;padding:7px 13px;border-radius:7px;cursor:pointer;transition:all .18s;white-space:nowrap}
.lnd-nl:hover,.lnd-nl.active{color:var(--txt);background:var(--glass)}
.lnd-nl.active{color:var(--acc2)}
.lnd-hero{flex:1;display:flex;align-items:center;justify-content:center;padding:32px 4%}
.lnd-card{display:flex;border:1px solid var(--bdr);border-radius:18px;overflow:hidden;width:100%;max-width:1100px;min-height:400px;background:var(--sur)}
.lnd-card::after{display:none}
.lnd-card-left{flex:0 0 50%;padding:44px 48px;display:flex;flex-direction:column;justify-content:center;align-items:center;background:var(--sur)}
.lnd-card-right{flex:1;overflow:hidden;position:relative}
.lnd-hero-img{width:100%;height:100%;object-fit:cover;display:block}
.lnd-card-right::before{content:"";position:absolute;inset:0;background:linear-gradient(to right,var(--sur) 0%,rgba(13,13,21,.7) 30%,transparent 70%);pointer-events:none;z-index:1}
.lnd-mob-logo{display:none}
.lnd-logo{font-family:"Rajdhani",sans-serif;font-size:38px;font-weight:700;color:var(--txt);margin-bottom:26px;letter-spacing:-1px}
.lnd-logo b{color:var(--acc2)}
.lnd-search-row{display:flex;width:100%;max-width:380px;margin-bottom:12px;border-radius:8px;overflow:hidden;border:1.5px solid var(--bdr);background:var(--sur2)}
.lnd-inp{flex:1;padding:11px 14px;border:none;background:transparent;color:var(--txt);font:14px "Nunito",sans-serif;outline:none;min-width:0}
.lnd-inp::placeholder{color:var(--dim)}
.lnd-sbtn{background:var(--acc);border:none;padding:0 14px;cursor:pointer;color:#fff;display:flex;align-items:center;transition:background .2s;flex-shrink:0}
.lnd-sbtn:hover{background:var(--acc2)}
.lnd-topsearch{font-size:12px;color:var(--dim);margin-bottom:26px;max-width:380px;width:100%;line-height:2}
.lnd-tslabel{font-weight:800;color:var(--txt);margin-right:4px}
.lnd-ts{background:none;border:none;color:var(--dim);font:12px "Nunito",sans-serif;cursor:pointer;padding:0 2px;transition:color .18s}
.lnd-ts:hover{color:var(--acc2)}
.lnd-watchbtn{display:inline-flex;align-items:center;gap:10px;background:var(--acc);color:#fff;border:none;padding:13px 24px;border-radius:8px;font:700 14px "Nunito",sans-serif;cursor:pointer;transition:background .2s,transform .15s;width:fit-content}
.lnd-watchbtn:hover{background:var(--acc2);transform:translateY(-2px)}
.lnd-mob-img-wrap{display:none}
.lnd-about{padding:36px 4%;border-top:1px solid var(--bdr);background:var(--sur)}
.lnd-about-inner{max-width:860px;margin:0 auto}
.lnd-about-h{font-family:"Rajdhani",sans-serif;font-size:19px;font-weight:700;color:var(--txt);margin-bottom:12px}
.lnd-about-p{font-size:13px;color:var(--dim);line-height:1.8;margin-bottom:10px}
.lnd-qa{margin-top:14px}
.lnd-q{font-size:14px;font-weight:800;color:var(--txt);margin:14px 0 5px}
.lnd-qn{color:var(--acc2);margin-right:4px}
.lnd-faq-section{padding:36px 4%;border-top:1px solid var(--bdr)}
.lnd-faq-list{display:flex;flex-direction:column;gap:8px;margin-top:14px;max-width:860px}
.lnd-faq-item{background:var(--sur2);border:1px solid var(--bdr);border-radius:10px;overflow:hidden;transition:border-color .2s}
.lnd-faq-item.open{border-color:rgba(124,58,237,.4)}
.lnd-faq-q{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:14px 16px;cursor:pointer;font-size:13.5px;font-weight:700;color:var(--txt);user-select:none}
.lnd-faq-arr{flex-shrink:0;transition:transform .25s;color:var(--dim)}
.lnd-faq-item.open .lnd-faq-arr{transform:rotate(180deg);color:var(--acc2)}
.lnd-faq-a{max-height:0;overflow:hidden;transition:max-height .3s ease,padding .3s;font-size:13px;color:var(--dim);line-height:1.75;padding:0 16px}
.lnd-faq-item.open .lnd-faq-a{max-height:120px;padding:0 16px 14px}
@media(max-width:768px){
  .lnd-nav{display:none}
  .lnd-hero{padding:0}
  .lnd-card{flex-direction:column;min-height:unset;border:none;border-radius:0;background:var(--bg)}
  .lnd-card-left{flex:none;padding:36px 24px 32px;align-items:center;background:var(--bg);width:100%;box-sizing:border-box}
  .lnd-card-right{display:none}
  .lnd-mob-logo{display:none}

  .lnd-search-row{max-width:100%;width:100%;border-radius:12px;border:1.5px solid var(--bdr);background:var(--sur)}
  .lnd-inp{padding:14px 16px;font-size:15px}
  .lnd-sbtn{padding:0 18px;border-radius:0 10px 10px 0}
  .lnd-topsearch{max-width:100%;width:100%;font-size:13px;line-height:2.1;text-align:left}
  .lnd-tslabel{font-size:13px;font-weight:800}
  .lnd-watchbtn{width:100%;justify-content:center;padding:16px;border-radius:12px;font-size:16px;margin-top:4px}
  .lnd-about,.lnd-faq-section{padding:28px 5%}
}

.spin{display:flex;gap:7px;align-items:center;justify-content:center;padding:64px 20px}
.spin span{width:9px;height:9px;background:var(--acc);border-radius:50%;animation:sp .75s infinite alternate}
.spin span:nth-child(2){animation-delay:.2s;background:var(--acc2)}
.spin span:nth-child(3){animation-delay:.4s;background:var(--pink)}
@keyframes sp{from{opacity:.2;transform:scale(.8)}to{opacity:1;transform:scale(1.25)}}

.dhero{position:relative;height:340px;overflow:hidden}
.dhero-bg{position:absolute;inset:0;background-size:cover;background-position:center 15%;filter:blur(7px) brightness(.28);transform:scale(1.09)}
.dhero-grad{position:absolute;inset:0;background:linear-gradient(0deg,var(--bg) 0%,transparent 52%),linear-gradient(90deg,rgba(5,5,10,.9) 0%,transparent 64%)}
.dhero-cnt{position:relative;z-index:2;height:100%;display:flex;align-items:flex-end;padding:0 5% 24px;gap:18px}
.dposter{width:120px;min-width:120px;border-radius:8px;box-shadow:0 6px 26px rgba(0,0,0,.8);border:2px solid var(--bdr)}
.dinfo{flex:1;min-width:0}
.dtitle{font-family:'Rajdhani',sans-serif;font-size:clamp(18px,3.5vw,34px);font-weight:700;color:#fff;margin-bottom:8px;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical}
.dnative{font-size:13px;color:var(--dim);margin-bottom:6px}
.dmeta{display:flex;flex-wrap:wrap;gap:5px;margin-bottom:12px}
.chip{background:var(--glass);border:1px solid var(--bdr);border-radius:5px;padding:3px 9px;font-size:11px;font-weight:700;color:var(--dim)}
.chip.sc{color:#fbbf24;border-color:rgba(251,191,36,.25)}
.dbody{padding:20px 4%}
.dsynopsis{font-size:13px;line-height:1.78;color:#aaa;max-width:780px;margin-bottom:22px}
.genres{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:22px}
.gtag{background:rgba(124,58,237,.12);border:1px solid rgba(124,58,237,.28);color:var(--acc2);border-radius:20px;padding:4px 12px;font-size:11px;font-weight:700;cursor:pointer;transition:background .18s;touch-action:manipulation}
.gtag:hover{background:rgba(124,58,237,.25)}

.ep-sec{margin-bottom:28px}
.ep-hdr{display:flex;align-items:center;justify-content:space-between;margin-bottom:11px;flex-wrap:wrap;gap:8px}
.ep-hdr-title{font-family:'Rajdhani',sans-serif;font-size:18px;font-weight:700}
.ltog{display:flex;gap:3px;background:var(--sur);border:1px solid var(--bdr);border-radius:8px;padding:3px}
.lbtn{background:none;border:none;color:var(--dim);font:800 11px 'Nunito',sans-serif;padding:5px 13px;border-radius:6px;cursor:pointer;letter-spacing:.5px;transition:all .18s;touch-action:manipulation}
.lbtn.on{background:var(--acc);color:#fff}
.ep-range-bar{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:12px}
.ep-range-btn{background:var(--glass);border:1px solid var(--bdr);color:var(--dim);font:700 11px 'Nunito',sans-serif;padding:5px 12px;border-radius:6px;cursor:pointer;transition:all .15s;white-space:nowrap}
.ep-range-btn:hover{border-color:var(--acc);color:var(--txt)}
.ep-range-btn.active{background:linear-gradient(135deg,var(--acc),var(--acc2));border-color:transparent;color:#fff}
.epgrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(58px,1fr));gap:6px}
.epbtn{background:var(--sur2);border:1px solid var(--bdr);color:var(--dim);font:700 13px 'Nunito',sans-serif;padding:9px 4px;border-radius:6px;cursor:pointer;text-align:center;transition:all .18s;touch-action:manipulation}
.epbtn:hover,.epbtn.on{background:var(--acc);border-color:var(--acc);color:#fff;box-shadow:0 3px 12px var(--glow)}
.epbtn:active{transform:scale(.92)}

/* Watch layout */
.wlayout{display:grid;grid-template-columns:1fr 290px;gap:18px;padding:16px 4%}
.wlayout.theatre{grid-template-columns:1fr;max-width:1100px;margin:0 auto}
.wlayout.theatre .sbar{display:none!important}
.wlayout.theatre+.mob-ep-wrap{display:block}
.pwrap{background:#000;border-radius:10px;overflow:hidden;aspect-ratio:16/9;position:relative;box-shadow:0 6px 32px rgba(0,0,0,.8);width:100%}
.pwrap iframe{width:100%;height:100%;border:none;display:block;position:absolute;inset:0}
.pload{position:absolute;inset:0;background:#080810;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;padding:20px;text-align:center;z-index:2}

.winfo{margin-top:14px;min-width:0;overflow:hidden}
.wt{font-family:'Rajdhani',sans-serif;font-size:20px;font-weight:700;margin-bottom:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:100%}
.wet{font-size:12px;color:var(--dim);margin-bottom:12px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:100%}
.wnav{display:flex;gap:6px;align-items:center;flex-wrap:wrap;max-width:100%}

.wctrl{background:none;border:1px solid var(--bdr);color:var(--dim);font:700 11px 'Nunito',sans-serif;padding:5px 10px;border-radius:6px;cursor:pointer;transition:all .18s;touch-action:manipulation;display:flex;align-items:center;gap:4px;white-space:nowrap}
.wctrl:hover{border-color:var(--acc);color:var(--acc2)}
.wctrl.on{border-color:var(--acc);color:var(--acc2);background:rgba(124,58,237,.12)}

.sbar-title{font-family:'Rajdhani',sans-serif;font-size:14px;font-weight:700;margin-bottom:9px;display:flex;align-items:center;gap:7px;overflow:hidden}
.eplist{display:flex;flex-direction:column;gap:3px;max-height:480px;overflow-y:auto;padding-right:2px;-webkit-overflow-scrolling:touch}
.eplist::-webkit-scrollbar{width:3px}
.eplist::-webkit-scrollbar-track{background:var(--sur);border-radius:99px}
.eplist::-webkit-scrollbar-thumb{background:var(--acc);border-radius:99px}
.epli{display:flex;align-items:center;gap:7px;background:var(--sur2);border:1px solid var(--bdr);border-radius:6px;padding:7px 9px;cursor:pointer;font-size:12px;font-weight:600;transition:all .18s;overflow:hidden;touch-action:manipulation}
.epli:hover,.epli.on{background:rgba(124,58,237,.17);border-color:var(--acc);color:var(--acc2)}
.epli:active{transform:scale(.97)}
.epnum{width:24px;min-width:24px;height:24px;background:var(--glass);border-radius:4px;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:800;color:var(--acc2)}
.epli.on .epnum{background:var(--acc);color:#fff}
.epitxt{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.mob-ep-wrap{display:none;padding:0 4% 24px}
.mob-ep-title{font-family:'Rajdhani',sans-serif;font-size:16px;font-weight:700;margin-bottom:9px}

.kb-hint{font-size:10px;color:var(--dim);padding:6px 4%;display:flex;gap:12px;flex-wrap:wrap}
.kb-hint span{display:flex;align-items:center;gap:4px}
.kb-key{background:var(--sur2);border:1px solid var(--bdr);border-radius:4px;padding:2px 6px;font-size:9px;font-weight:800;font-family:'Rajdhani',sans-serif}

.perror{display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;background:#080810;gap:10px;padding:20px;text-align:center}
.perror h4{font-family:'Rajdhani',sans-serif;font-size:16px;font-weight:700;color:#fff}
.perror p{font-size:12px;color:var(--dim);max-width:210px;line-height:1.6}

.srh-hdr{padding:20px 4% 0;margin-bottom:14px}
.srh-title{font-family:'Rajdhani',sans-serif;font-size:18px;font-weight:700;color:var(--dim)}
.srh-title span{color:var(--acc2)}

.empty{text-align:center;padding:60px 20px;grid-column:1/-1}
.empty-ic2{width:80px;height:80px;border-radius:50%;background:linear-gradient(135deg,rgba(124,58,237,.12),rgba(168,85,247,.08));border:1px solid rgba(124,58,237,.2);display:flex;align-items:center;justify-content:center;margin:0 auto 18px}
.empty h3{font-family:'Rajdhani',sans-serif;font-size:20px;color:var(--dim);margin-bottom:6px}
.empty p{font-size:13px;color:var(--dim)}
.empty a{color:var(--acc2)}

/* Tabs */
.tab-bar{display:flex;gap:4px;border-bottom:1px solid var(--bdr);margin-bottom:18px;overflow-x:auto;scrollbar-width:none}
.tab-bar::-webkit-scrollbar{display:none}
.tab-btn{background:none;border:none;border-bottom:2px solid transparent;color:var(--dim);font:700 12px 'Nunito',sans-serif;padding:8px 14px;cursor:pointer;white-space:nowrap;transition:all .18s;touch-action:manipulation;margin-bottom:-1px}
.tab-btn:hover{color:var(--txt)}
.tab-btn.on{color:var(--acc2);border-bottom-color:var(--acc2)}
.tab-panel{display:none}
.tab-panel.on{display:block}

.sentinel{height:1px;width:100%;grid-column:1/-1}

/* ── Community ── */
.comm-page{display:grid;grid-template-columns:300px 1fr;gap:28px;padding:28px 4% 60px;max-width:1200px;margin:0 auto;align-items:start}
.comm-sidebar{position:sticky;top:72px}
.comm-sidebar-box{background:var(--sur2);border:1px solid var(--bdr);border-radius:14px;padding:22px 20px}
.comm-title{font-family:'Rajdhani',sans-serif;font-size:22px;font-weight:700;margin-bottom:6px;display:flex;align-items:center;gap:8px}
.comm-title::before{content:'';width:4px;height:20px;background:linear-gradient(180deg,var(--acc),var(--pink));border-radius:99px;display:inline-block;flex-shrink:0}
.comm-sub{font-size:12px;color:var(--dim);line-height:1.7;margin-bottom:0}
.comm-sidebar-divider{height:1px;background:var(--bdr);margin:18px 0}
.comm-stat{display:flex;align-items:center;gap:9px;font-size:12px;color:var(--dim);margin-bottom:10px}
.comm-stat svg{flex-shrink:0;color:var(--acc2)}
.comm-stat strong{color:var(--txt)}
.comm-feed-wrap{min-width:0}
.comm-feed-hdr{display:flex;align-items:center;justify-content:space-between;margin-bottom:14px}
.comm-feed-title{font-family:'Rajdhani',sans-serif;font-size:17px;font-weight:700}
.comm-mob-hdr{display:none;margin-bottom:14px}
.comm-mob-hdr h2{font-family:'Rajdhani',sans-serif;font-size:20px;font-weight:700;display:flex;align-items:center;gap:8px}
.comm-mob-hdr h2::before{content:'';width:4px;height:18px;background:linear-gradient(180deg,var(--acc),var(--pink));border-radius:99px;display:inline-block;flex-shrink:0}
.comm-mob-hdr p{font-size:11px;color:var(--dim);margin-top:4px}
@media(max-width:900px){
  .comm-mob-hdr{display:block}
}
.comm-feed{display:grid;grid-template-columns:1fr 1fr;gap:12px}
.comm-card{background:var(--sur2);border:1px solid var(--bdr);border-radius:12px;padding:14px 16px;position:relative;animation:cin .35s ease forwards;opacity:0;transform:translateY(8px)}
.comm-card-hdr{display:flex;align-items:center;gap:9px;margin-bottom:9px}
.comm-avatar{width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,var(--acc),var(--pink));display:flex;align-items:center;justify-content:center;font:800 13px 'Rajdhani',sans-serif;color:#fff;flex-shrink:0;text-transform:uppercase}
.comm-author{font:800 13px 'Nunito',sans-serif;color:var(--txt);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:110px}
.comm-time{font-size:10px;color:var(--dim);margin-left:auto;white-space:nowrap}
.comm-body{font-size:13px;color:#ccc;line-height:1.65;word-break:break-word;white-space:pre-wrap}
.comm-empty{text-align:center;padding:40px 20px;color:var(--dim);font-size:13px;grid-column:1/-1}
.comm-loader{text-align:center;padding:24px;color:var(--dim);font-size:12px;grid-column:1/-1}
.comm-form-row{display:flex;gap:8px;margin-bottom:10px}
.comm-input{flex:1;background:var(--glass);border:1px solid var(--bdr);border-radius:8px;color:var(--txt);font:600 13px 'Nunito',sans-serif;padding:9px 12px;outline:none;-webkit-appearance:none;transition:border-color .2s}
.comm-input:focus{border-color:var(--acc)}
.comm-input::placeholder{color:var(--dim)}
.comm-textarea{width:100%;background:var(--glass);border:1px solid var(--bdr);border-radius:8px;color:var(--txt);font:600 13px 'Nunito',sans-serif;padding:10px 12px;outline:none;resize:none;min-height:80px;-webkit-appearance:none;transition:border-color .2s;box-sizing:border-box}
.comm-textarea:focus{border-color:var(--acc)}
.comm-textarea::placeholder{color:var(--dim)}
.comm-form-footer{display:flex;align-items:center;justify-content:space-between;gap:8px;flex-wrap:wrap}
.comm-count{font-size:11px;color:var(--dim);font-weight:700}
.comm-count.warn{color:#f59e0b}
.comm-count.err{color:#ef4444}
.comm-post-btn{background:linear-gradient(135deg,var(--acc),var(--acc2));color:#fff;border:none;font:800 12px 'Nunito',sans-serif;padding:8px 20px;border-radius:8px;cursor:pointer;transition:transform .2s,box-shadow .2s;touch-action:manipulation;width:100%;margin-top:12px}
.comm-post-btn:hover{transform:translateY(-1px);box-shadow:0 4px 14px var(--glow)}
.comm-post-btn:disabled{opacity:.45;cursor:not-allowed;transform:none;box-shadow:none}
@media(max-width:900px){
  .comm-page{grid-template-columns:1fr;padding:18px 3% 80px;gap:18px}
  .comm-sidebar{display:none}
  .comm-feed{grid-template-columns:1fr 1fr}
}
@media(max-width:520px){
  .comm-feed{grid-template-columns:1fr}
}

/* Community modal */
.comm-fab{position:fixed;bottom:24px;right:24px;width:52px;height:52px;background:linear-gradient(135deg,var(--acc),var(--acc2));border:none;border-radius:50%;display:flex;align-items:center;justify-content:center;cursor:pointer;box-shadow:0 4px 18px var(--glow);z-index:600;touch-action:manipulation;transition:transform .2s,box-shadow .2s}
.comm-fab:hover{transform:translateY(-2px) scale(1.07);box-shadow:0 8px 26px var(--glow)}
.comm-fab:active{transform:scale(.93)}
.comm-modal-bg{position:fixed;inset:0;background:rgba(0,0,0,.72);z-index:800;display:flex;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);animation:fadein .2s ease}
@keyframes fadein{from{opacity:0}to{opacity:1}}
.comm-modal{background:var(--sur2);border:1px solid var(--bdr);border-radius:16px;padding:24px;width:100%;max-width:480px;animation:slideup .22s ease}
@keyframes slideup{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:translateY(0)}}
.comm-modal-hdr{display:flex;align-items:center;justify-content:space-between;margin-bottom:18px}
.comm-modal-title{font-family:'Rajdhani',sans-serif;font-size:18px;font-weight:700}
.comm-modal-close{background:none;border:none;color:var(--dim);cursor:pointer;padding:4px;display:flex;align-items:center;transition:color .18s;touch-action:manipulation}
.comm-modal-close:hover{color:var(--txt)}

footer{background:var(--sur);border-top:1px solid var(--bdr);padding:28px 5%;text-align:center;margin-top:32px}
.flogo{font-family:'Rajdhani',sans-serif;font-size:20px;font-weight:700;margin-bottom:9px}
.flogo b{color:var(--acc2)}
.flinks{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin:9px 0}
.flinks a{color:var(--dim);font-size:12px;transition:color .18s;cursor:pointer}
.flinks a:hover{color:var(--acc2)}
.ftxt{color:var(--dim);font-size:12px;margin:4px 0}

#btt{position:fixed;bottom:18px;right:18px;width:38px;height:38px;background:linear-gradient(135deg,var(--acc),var(--acc2));color:#fff;border:none;border-radius:50%;display:none;align-items:center;justify-content:center;cursor:pointer;box-shadow:0 3px 14px var(--glow);z-index:500;touch-action:manipulation}
#btt:hover{transform:translateY(-2px)}

.post-footer,.date-header,.status-msg-wrap,.blog-pager,.widget:not(#Blog1){display:none!important}

@media(max-width:860px){
  .wlayout{grid-template-columns:1fr}
  .sbar{display:none}
  .mob-ep-wrap{display:block}
}
@media(max-width:600px){
  #hdr{padding:0 3%;gap:6px;height:52px}
  #app{padding-top:52px}
  #mob-drawer{top:52px}
  .logo{font-size:20px}
  .hnav,.hnav+#rand-btn{display:none}
  #rand-btn{display:none}
  #mob-btn{display:flex}
  .sw{max-width:none;flex:1}
  #pwa-btn{display:none!important}
  .grid{grid-template-columns:repeat(2,1fr);gap:9px}
  .hero{height:280px}
  .hero-desc{display:none}
  .dhero{height:270px}
  .dhero-cnt{padding:0 3% 16px;gap:12px}
  .dposter{width:82px;min-width:82px}
  .dtitle{font-size:17px}
  .sec{padding:0 3% 22px}
  .dbody{padding:16px 3%}
  .epgrid{grid-template-columns:repeat(auto-fill,minmax(50px,1fr));gap:5px}
  .wlayout{padding:10px 3%}
  .mob-ep-wrap{padding:0 3% 20px}
  .hero-btns .bs{display:none}
  .kb-hint{display:none}
  #asearch-panel{top:52px}
  #mob-drawer{top:52px}
  .wt{font-size:16px}
  .wet{font-size:11px}
  .wnav{gap:4px}
  .wctrl{font-size:10px;padding:4px 7px}
  .ltog{margin-left:0!important}
}
@media(max-width:360px){
  .grid{grid-template-columns:repeat(2,1fr);gap:7px}
  .dposter{width:70px;min-width:70px}
}

body.script:
//
(function(){
  var fbCfg={
    apiKey:'AIzaSyD6bnfVL4XZhdpAPtM2_qVrCNNc9aSxve8',
    authDomain:'anidexz.firebaseapp.com',
    databaseURL:'https://anidexz-default-rtdb.firebaseio.com',
    projectId:'anidexz',
    storageBucket:'anidexz.firebasestorage.app',
    messagingSenderId:'744070068034',
    appId:'1:744070068034:web:76d7007747567d49453adb'
  };
  if(!firebase.apps.length)firebase.initializeApp(fbCfg);
  window._fbDb=firebase.database();
})();
//

//
(function(){
'use strict';

/* ─── m=1 redirect fix ─── */
(function(){
  var loc=window.location,s=loc.search;
  if(s&&/[?&]m=1(&|$)/.test(s)){
    var c=s.replace(/\?m=1(&|$)/,function(_,q){return q?'?':'';}).replace(/&m=1(&|$)/,function(_,q){return q?'&':'';});
    window.history.replaceState(null,'',loc.pathname+c+loc.hash);
  }
})();

/* ─── Constants ─── */
var AL='https://graphql.anilist.co';
var _b=(function(){var p=['https://episode-id','onrender.com','get-link'];return p[0]+'.'+p[1]+'/'+p[2];})();
var _c=(function(){var p=['https://megaplay','buzz','stream','s-2'];return p[0]+'.'+p[1]+'/'+p[2]+'/'+p[3];})();
var STORE={WL:'anz_wl',CW:'anz_cw',RV:'anz_rv'};

var GENRES=['Action','Adventure','Comedy','Drama','Fantasy','Horror','Mystery',
  'Psychological','Romance','Sci-Fi','Slice of Life','Sports','Supernatural',
  'Thriller','Ecchi','Harem','Isekai','Mecha','Military','Music','School','Shounen',
  'Shoujo','Seinen','Josei'];

/* ─── State ─── */
var S={view:'home',id:null,name:null,titleAlt:null,ep:null,lang:'sub',q:''};
var cache={anime:{},eps:{}};
var _cp={name:'',titleAlt:'',ep:1,lang:'sub'};
var _heroTick=null,_heroList=[],_heroIdx=0;
var _io=null;
var _pageState={num:1,loading:false,done:false};
var _filter={genre:'',type:'',status:'',year:'',score:'',order:'SCORE_DESC'};
var _anTimer=null,_anEnabled=false;
var _theatre=false;
var _pwaPrompt=null;

/* ─── AniList GraphQL helper ─── */
function cleanVars(obj){
  var out={};
  var keys=Object.keys(obj);
  for(var i=0;i<keys.length;i++){
    var k=keys[i];
    if(obj[k]!==null&&obj[k]!==undefined)out[k]=obj[k];
  }
  return out;
}
function _alFetch(query,vars){
  var body=JSON.stringify({query:query,variables:vars});
  return fetch(AL,{
    method:'POST',mode:'cors',credentials:'omit',
    headers:{'Content-Type':'application/json','Accept':'application/json'},
    body:body
  });
}
function _alFetchProxy(query,vars){
  /* Fallback via corsproxy.io when direct fetch is blocked */
  var body=JSON.stringify({query:query,variables:vars});
  return fetch('https://corsproxy.io/?'+encodeURIComponent(AL),{
    method:'POST',
    headers:{'Content-Type':'application/json','Accept':'application/json'},
    body:body
  });
}
function alQuery(query,variables){
  var vars=cleanVars(variables||{});
  return _alFetch(query,vars)
    .catch(function(){return _alFetchProxy(query,vars);})
    .then(function(r){
      if(r.status===429){
        return new Promise(function(res){setTimeout(res,2500);})
          .then(function(){return alQuery(query,variables);});
      }
      return r.json();
    }).then(function(d){
      if(d.errors&&d.errors.length)throw new Error(d.errors[0].message||'GraphQL error');
      if(!d.data)throw new Error('No data returned');
      return d.data;
    });
}

/* ─── GraphQL Queries ─── */
function Q_LIST(){
  return [
    'query($page:Int $perPage:Int $sort:[MediaSort] $format:MediaFormat',
    '$status:MediaStatus $season:MediaSeason $seasonYear:Int',
    '$genre_in:[String] $search:String $averageScore_greater:Int){',
    'Page(page:$page perPage:$perPage){',
    'pageInfo{hasNextPage total}',
    'media(type:ANIME sort:$sort format:$format status:$status',
    'season:$season seasonYear:$seasonYear genre_in:$genre_in search:$search',
    'averageScore_greater:$averageScore_greater){',
    'id idMal title{romaji english native}',
    'coverImage{extraLarge large medium}',
    'bannerImage format status episodes season seasonYear',
    'averageScore popularity favourites genres',
    'studios(isMain:true){nodes{id name}}',
    'nextAiringEpisode{episode airingAt}',
    '}}}'
  ].join(' ');
}

function Q_DETAIL(){
  return [
    'query($id:Int){',
    'Media(id:$id type:ANIME){',
    'id idMal title{romaji english native}',
    'coverImage{extraLarge large medium}',
    'bannerImage format status episodes duration',
    'season seasonYear',
    'startDate{year month day} endDate{year month day}',
    'averageScore meanScore popularity favourites trending',
    'genres description(asHtml:false) synonyms source countryOfOrigin',
    'studios(isMain:true){nodes{id name isAnimationStudio}}',
    'nextAiringEpisode{episode airingAt}',
    'trailer{id site thumbnail}',
    'tags{name rank isMediaSpoiler}',
    'characters(sort:[ROLE RELEVANCE] perPage:20){',
      'edges{',
        'role',
        'node{id name{full native} image{large medium}}',
        'voiceActors(language:JAPANESE){id name{full native} image{large medium}}',
      '}',
    '}',
    'staff(sort:[RELEVANCE] perPage:12){',
      'edges{ role node{id name{full} image{large medium}} }',
    '}',
    'relations{',
      'edges{',
        'relationType(version:2)',
        'node{id title{romaji english} coverImage{medium} format type}',
      '}',
    '}',
    'recommendations(sort:RATING_DESC perPage:10){',
      'nodes{mediaRecommendation{id title{romaji english} coverImage{medium large} format averageScore}}',
    '}',
    'externalLinks{url site type}',
    '}}'
  ].join(' ');
}

/* ─── Progress bar ─── */
var _pt;
function pbStart(){var pbar=document.getElementById('pbar');if(!pbar)return;pbar.style.cssText='opacity:1;width:0%';pbar.classList.remove('done');var w=0;clearInterval(_pt);_pt=setInterval(function(){w+=Math.random()*15;if(w>82)w=82;pbar.style.width=w+'%';},180);}
function pbDone(){var pbar=document.getElementById('pbar');clearInterval(_pt);if(!pbar)return;pbar.classList.add('done');setTimeout(function(){pbar.style.cssText='width:0%;opacity:0';pbar.classList.remove('done');},480);}

/* ─── Storage ─── */
function lsGet(k){try{return JSON.parse(localStorage.getItem(k)||'null');}catch(e){return null;}}
function lsSet(k,v){try{localStorage.setItem(k,JSON.stringify(v));}catch(e){}}

/* ─── Toast ─── */
function toast(msg,dur){
  var w=document.getElementById('toast-wrap');if(!w)return;
  var t=document.createElement('div');t.className='toast';t.textContent=msg;
  w.appendChild(t);
  setTimeout(function(){t.classList.add('out');setTimeout(function(){if(t.parentNode)t.parentNode.removeChild(t);},380);},dur||2200);
}

/* ─── Watchlist ─── */
function getWL(){return lsGet(STORE.WL)||[];}
function isWL(id){return getWL().some(function(a){return a.id===id;});}
function toggleWL(item){
  var wl=getWL();var idx=-1;
  for(var i=0;i<wl.length;i++){if(wl[i].id===item.id){idx=i;break;}}
  if(idx>=0){wl.splice(idx,1);lsSet(STORE.WL,wl);toast('Removed from My List');return false;}
  wl.unshift(item);lsSet(STORE.WL,wl);toast('\u2713 Added to My List');return true;
}

/* ─── Recently Viewed ─── */
function addRV(id,title,titleAlt,poster){
  var rv=lsGet(STORE.RV)||[];
  rv=rv.filter(function(a){return a.id!==id;});
  rv.unshift({id:id,title:title,titleAlt:titleAlt,poster:poster});
  if(rv.length>12)rv=rv.slice(0,12);
  lsSet(STORE.RV,rv);
}

/* ─── Continue Watching ─── */
function saveCW(id,ep,lang,title,titleAlt,poster){
  var cw=lsGet(STORE.CW)||{};
  cw[String(id)]={id:id,ep:ep,lang:lang,title:title,titleAlt:titleAlt,poster:poster,ts:Date.now()};
  lsSet(STORE.CW,cw);
}
function getCW(){
  var cw=lsGet(STORE.CW)||{};
  var arr=Object.keys(cw).map(function(k){return cw[k];});
  arr.sort(function(a,b){return b.ts-a.ts;});
  return arr.slice(0,8);
}

/* ─── Helpers ─── */
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function alImg(m,size){
  if(!m||!m.coverImage)return'https://placehold.co/300x420/0d0d15/555577?text=No+Image';
  return m.coverImage[size||'large']||m.coverImage.medium||'https://placehold.co/300x420/0d0d15/555577?text=No+Image';
}
function alTitle(m){return(m&&(m.title.english||m.title.romaji))||'Unknown';}
function alTitleAlt(m){return(m&&(m.title.romaji||m.title.english))||'';}
function scoreDisp(m){if(!m)return'N/A';var s=m.averageScore||m.meanScore;return s?s:'N/A';}
function fmtFormat(f){return(f||'').replace(/_/g,' ');}
function spin(){return'<div class="spin"><span></span><span></span><span></span></div>';}
function emptyHTML(title,body){
  return'<div class="empty"><div class="empty-ic"><svg width="22" height="22" fill="none" stroke="var(--dim)" stroke-width="2" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><circle cx="12" cy="16" r=".5" fill="var(--dim)"/></svg></div><h3>'+esc(title)+'</h3><p>'+body+'</p></div>';
}
function heartSVG(on){
  return'<svg width="11" height="11" fill="'+(on?'#ec4899':'none')+'" stroke="'+(on?'#ec4899':'currentColor')+'" stroke-width="2" viewBox="0 0 24 24"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></svg>';
}
function addSkels(g,n){for(var i=0;i<n;i++){var s=document.createElement('div');s.className='card-skel';g.appendChild(s);}}

/* ─── Skeleton helpers ─── */
function skelImg(url,alt,cls,w,h){
  return'<img src="'+esc(url||'')+'" alt="'+esc(alt||'')+'" loading="lazy" onerror="this.src=\'https://placehold.co/'+w+'x'+h+'/0d0d15/555577?text=N/A\'" class="'+cls+'"/>';
}

/* ─── Card ─── */
function makeCard(m,di){
  var title=alTitle(m);
  var titleAlt=alTitleAlt(m);
  var id=m.id;
  var wl=isWL(id);
  var score=scoreDisp(m);
  var fmt=fmtFormat(m.format);
  var d=document.createElement('div');d.className='card';d.style.animationDelay=(di||0)+'ms';
  d.innerHTML=
    (fmt?'<span class="cbadge l">'+esc(fmt)+'</span>':'')+
    (score&&score!=='N/A'?'<span class="cbadge r">&#9733; '+score+'</span>':'')+
    '<button class="heart-btn'+(wl?' on':'')+'" title="'+(wl?'Remove from My List':'Add to My List')+'">'+heartSVG(wl)+'</button>'+
    skelImg(alImg(m),title,'',300,420)+
    '<div class="cov"><p class="ctitle">'+esc(title)+'</p><span class="cwbtn">&#9654; Watch</span></div>';
  var hb=d.querySelector('.heart-btn');
  hb.addEventListener('click',function(e){
    e.stopPropagation();
    var added=toggleWL({id:id,title:title,titleAlt:titleAlt,poster:alImg(m),score:score,type:fmt});
    hb.classList.toggle('on',added);hb.innerHTML=heartSVG(added);
  });
  d.addEventListener('click',function(){go('anime',{id:id,name:title,titleAlt:titleAlt});});
  requestAnimationFrame(function(){d.classList.add('in');});
  return d;
}
function appendCards(g,list){list.forEach(function(m,i){g.appendChild(makeCard(m,i*34));});}

/* ─── Section builder ─── */
function makeSection(title,view,list,gid){
  var div=document.createElement('div');div.className='sec';
  div.innerHTML='<div class="sec-hdr"><h2 class="sec-title">'+esc(title)+'</h2><button class="sec-all" data-v="'+view+'">View All</button></div><div class="grid" id="'+gid+'"></div>';
  div.querySelector('.sec-all').addEventListener('click',function(){go(this.dataset.v);});
  appendCards(div.querySelector('.grid'),list);
  return div;
}

/* ─── Horizontal small-card section ─── */
function makeHSection(sectionTitle,items,makeItemFn){
  var sec=document.createElement('div');sec.className='sec';
  sec.innerHTML='<div class="sec-hdr"><h2 class="sec-title">'+esc(sectionTitle)+'</h2></div>';
  var outer=document.createElement('div');outer.className='hscroll-outer';
  var row=document.createElement('div');row.className='hscroll';
  items.forEach(function(it){var el=makeItemFn(it);if(el)row.appendChild(el);});
  outer.appendChild(row);sec.appendChild(outer);return sec;
}

/* ─── Genre filter row ─── */
function buildGenreRow(container,onChange){
  var row=document.createElement('div');row.className='genre-row';
  var all=document.createElement('button');all.className='gbtn on';all.textContent='All';all.dataset.gid='';
  row.appendChild(all);
  GENRES.forEach(function(g){
    var btn=document.createElement('button');btn.className='gbtn';btn.textContent=g;btn.dataset.gid=g;
    row.appendChild(btn);
  });
  if(_filter.genre){
    row.querySelectorAll('.gbtn').forEach(function(b){b.classList.toggle('on',b.dataset.gid===_filter.genre);});
  }
  row.addEventListener('click',function(e){
    var btn=e.target.closest('.gbtn');if(!btn)return;
    row.querySelectorAll('.gbtn').forEach(function(b){b.classList.remove('on');});
    btn.classList.add('on');_filter.genre=btn.dataset.gid;onChange();
  });
  if(container.firstChild)container.insertBefore(row,container.firstChild);
  else container.appendChild(row);
  return row;
}

/* ─── AniList list vars builder ─── */
function buildVars(opts){
  /* Always include page/perPage */
  var v={page:(opts&&opts.page)||1, perPage:24};
  /* Sort - always required, default TRENDING_DESC */
  var sort=(opts&&opts.sort)||_filter.order||'TRENDING_DESC';
  v.sort=[sort];
  /* Optional: only set if truthy - cleanVars will also strip nulls */
  if(opts&&opts.q)v.search=opts.q;
  if(_filter.type){v.format=_filter.type;}
  else if(opts&&opts.format){v.format=opts.format;}
  if(_filter.status){v.status=_filter.status;}
  else if(opts&&opts.status){v.status=opts.status;}
  if(opts&&opts.season){v.season=opts.season;}
  if(opts&&opts.seasonYear){v.seasonYear=opts.seasonYear;}
  else if(_filter.year){v.seasonYear=parseInt(_filter.year);}
  if(_filter.score){v.averageScore_greater=parseInt(_filter.score);}
  if(_filter.genre){v.genre_in=[_filter.genre];}
  else if(opts&&opts.genre_in){v.genre_in=opts.genre_in;}
  return v;
}
function hasFilters(){return !!(_filter.genre||_filter.type||_filter.status||_filter.year||_filter.score);}

/* ─── Infinite scroll ─── */
function initIO(gridId,fetchNextPage){
  if(_io){_io.disconnect();_io=null;}
  _pageState={num:1,loading:false,done:false};
  var g=document.getElementById(gridId);if(!g)return;
  var sentinel=document.createElement('div');sentinel.className='sentinel';
  if(g.parentNode)g.parentNode.insertBefore(sentinel,g.nextSibling);
  _io=new IntersectionObserver(function(entries){
    if(!entries[0].isIntersecting||_pageState.loading||_pageState.done)return;
    _pageState.loading=true;_pageState.num++;
    fetchNextPage(_pageState.num).then(function(list){
      _pageState.loading=false;
      if(!list||!list.length){_pageState.done=true;if(_io)_io.disconnect();return;}
      var g2=document.getElementById(gridId);if(g2)appendCards(g2,list);
    }).catch(function(){_pageState.loading=false;_pageState.done=true;if(_io)_io.disconnect();});
  },{threshold:0.1,rootMargin:'200px'});
  _io.observe(sentinel);
}

/* ─── PWA ─── */
(function(){
  try{
    var m={name:'anidexz',short_name:'anidexz',start_url:location.origin+location.pathname,display:'standalone',background_color:'#05050a',theme_color:'#05050a',description:'Watch anime online',
      icons:[{src:'https://placehold.co/192x192/7c3aed/fff?text=A',sizes:'192x192',type:'image/png'},{src:'https://placehold.co/512x512/7c3aed/fff?text=A',sizes:'512x512',type:'image/png'}]};
    var blob=new Blob([JSON.stringify(m)],{type:'application/manifest+json'});
    var lnk=document.createElement('link');lnk.rel='manifest';lnk.href=URL.createObjectURL(blob);document.head.appendChild(lnk);
  }catch(e){}
  window.addEventListener('beforeinstallprompt',function(e){e.preventDefault();_pwaPrompt=e;var btn=document.getElementById('pwa-btn');if(btn)btn.style.display='flex';});
  var pb=document.getElementById('pwa-btn');
  if(pb)pb.addEventListener('click',function(){if(!_pwaPrompt)return;_pwaPrompt.prompt();_pwaPrompt.userChoice.then(function(r){_pwaPrompt=null;if(r.outcome==='accepted'){toast('\u2713 anidexz installed!');pb.style.display='none';}});});
})();

/* ─── Advanced search panel setup ─── */
(function(){
  var ySel=document.getElementById('asp-year');
  if(ySel){var cy=new Date().getFullYear();for(var y=cy;y>=2000;y--){var op=document.createElement('option');op.value=y;op.textContent=y;ySel.appendChild(op);}}
  var panel=document.getElementById('asearch-panel');
  var asBtn=document.getElementById('asearch-btn');
  if(asBtn)asBtn.addEventListener('click',function(e){e.stopPropagation();panel.classList.toggle('open');asBtn.classList.toggle('on',panel.classList.contains('open'));});
  document.addEventListener('click',function(e){
    if(panel&&panel.classList.contains('open')&&!panel.contains(e.target)&&e.target!==asBtn){panel.classList.remove('open');if(asBtn)asBtn.classList.remove('on');}
  });
  var applyBtn=document.getElementById('asp-apply');
  if(applyBtn)applyBtn.addEventListener('click',function(){
    _filter.type=document.getElementById('asp-type').value;
    _filter.status=document.getElementById('asp-status').value;
    _filter.year=document.getElementById('asp-year').value;
    _filter.score=document.getElementById('asp-score').value;
    _filter.order=document.getElementById('asp-order').value||'SCORE_DESC';
    panel.classList.remove('open');if(asBtn)asBtn.classList.remove('on');
    if(S.view==='search')renderSearch(S.q);
    else if(S.view==='trending'||S.view==='movies')renderList(S.view);
    else{S.view='search';S.q='';renderSearch('');}
  });
  var resetBtn=document.getElementById('asp-reset');
  if(resetBtn)resetBtn.addEventListener('click',function(){
    _filter={genre:'',type:'',status:'',year:'',score:'',order:'SCORE_DESC'};
    ['asp-type','asp-status','asp-year','asp-score'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});
    document.getElementById('asp-order').value='SCORE_DESC';
    panel.classList.remove('open');if(asBtn)asBtn.classList.remove('on');
    toast('Filters reset');
    if(S.view==='search')renderSearch(S.q);
    else if(S.view==='trending'||S.view==='movies')renderList(S.view);
  });
})();

/* ─── Random anime ─── */
function goRandom(){
  toast('Finding random anime\u2026');pbStart();
  var page=Math.floor(Math.random()*50)+1;
  var idx=Math.floor(Math.random()*24);
  alQuery(Q_LIST(),{page:page,perPage:24,sort:['POPULARITY_DESC']}).then(function(d){
    pbDone();
    var list=d&&d.Page&&d.Page.media;
    if(!list||!list.length){toast('Nothing found');return;}
    var m=list[Math.min(idx,list.length-1)];
    go('anime',{id:m.id,name:alTitle(m),titleAlt:alTitleAlt(m)});
  }).catch(function(){pbDone();toast('Failed \u2014 try again');});
}
var rb=document.getElementById('rand-btn');if(rb)rb.addEventListener('click',goRandom);
var mrb=document.getElementById('mob-rand-btn');if(mrb)mrb.addEventListener('click',function(){closeDrawer();goRandom();});

/* ─── Keyboard shortcuts ─── */
document.addEventListener('keydown',function(e){
  if(S.view!=='watch')return;
  if(e.target.tagName==='INPUT'||e.target.tagName==='SELECT'||e.target.tagName==='TEXTAREA')return;
  switch(e.key){
    case 'ArrowLeft':e.preventDefault();if(S.ep>1)go('watch',{id:S.id,name:S.name,titleAlt:S.titleAlt,ep:S.ep-1,lang:S.lang});break;
    case 'ArrowRight':
      e.preventDefault();
      var eps=cache.eps[S.id];
      if(eps){var mx=eps.length;if(S.ep<mx)go('watch',{id:S.id,name:S.name,titleAlt:S.titleAlt,ep:S.ep+1,lang:S.lang});}
      break;
    case 'f':case 'F':
      e.preventDefault();
      var wrap=document.getElementById('pwrap');
      if(wrap){if(document.fullscreenElement)document.exitFullscreen();else if(wrap.requestFullscreen)wrap.requestFullscreen();}
      break;
    case 't':case 'T':e.preventDefault();toggleTheatre();break;
  }
});

/* ─── Theatre mode ─── */
function toggleTheatre(){
  _theatre=!_theatre;
  var layout=document.querySelector('.wlayout');
  var btn=document.getElementById('theatre-btn');
  if(layout)layout.classList.toggle('theatre',_theatre);
  if(btn){btn.classList.toggle('on',_theatre);btn.title=_theatre?'Exit Theatre (T)':'Theatre Mode (T)';}
}

/* ─── Auto-next ─── */
function clearAN(){clearInterval(_anTimer);_anTimer=null;}
function startAN(maxEp){
  if(!_anEnabled||!S.ep||S.ep>=maxEp)return;
  var count=5;clearAN();
  _anTimer=setInterval(function(){
    count--;toast('Next episode in '+count+'s');
    if(count<=0){clearAN();go('watch',{id:S.id,name:S.name,titleAlt:S.titleAlt,ep:S.ep+1,lang:S.lang});}
  },1000);
}

/* ─── Router ─── */
window.go=function go(view,extra,noScroll){
  S={view:view,id:null,name:null,titleAlt:null,ep:null,lang:S.lang||'sub',q:''};
  if(extra)for(var k in extra)S[k]=extra[k];
  if(view!=='search'){var si=document.getElementById('si');if(si)si.value='';}
  var asp=document.getElementById('asearch-panel');if(asp)asp.classList.remove('open');
  var asb=document.getElementById('asearch-btn');if(asb)asb.classList.remove('on');
  clearAN();if(_io){_io.disconnect();_io=null;}
  history.pushState(S,'',buildURL(S));
  syncNav();closeDrawer();render(noScroll);
}
function buildURL(s){
  var p=new URLSearchParams();
  if(s.view&&s.view!=='landing')p.set('v',s.view);
  if(s.id)p.set('id',s.id);
  if(s.name)p.set('n',s.name);
  if(s.titleAlt)p.set('na',s.titleAlt);
  if(s.ep)p.set('ep',s.ep);
  if(s.lang&&s.lang!=='sub')p.set('l',s.lang);
  if(s.q)p.set('q',s.q);
  var qs=p.toString();return location.pathname+(qs?'?'+qs:'');
}
function fromURL(){
  var p=new URLSearchParams(location.search);
  return{view:p.get('v')||'landing',id:p.get('id')?+p.get('id'):null,name:p.get('n')||null,titleAlt:p.get('na')||null,ep:p.get('ep')?+p.get('ep'):null,lang:p.get('l')||'sub',q:p.get('q')||''};
}
window.addEventListener('popstate',function(e){S=e.state||fromURL();syncNav();render(false);});
function syncNav(){document.querySelectorAll('.hn[data-v]').forEach(function(b){b.classList.toggle('on',b.dataset.v===S.view);});}

/* ─── Mobile drawer ─── */
var _drawer=document.getElementById('mob-drawer');
var _mobBtn=document.getElementById('mob-btn');
if(_mobBtn)_mobBtn.addEventListener('click',function(e){e.stopPropagation();if(_drawer)_drawer.classList.toggle('open');});
document.addEventListener('click',function(e){if(_drawer&&!_drawer.contains(e.target)&&e.target!==_mobBtn)_drawer.classList.remove('open');});
function closeDrawer(){if(_drawer)_drawer.classList.remove('open');}

/* ─── Render dispatcher ─── */
window.render=function render(noScroll){
  var app=document.getElementById('app');
  clearInterval(_heroTick);_heroTick=null;
  app.classList.add('fade');
  setTimeout(function(){
    var hdr=document.getElementById('hdr');if(hdr){if(S.view==='landing'){hdr.classList.add('hidden');app.style.paddingTop='0';}else{hdr.classList.remove('hidden');app.style.paddingTop='';}}app.innerHTML='';app.classList.remove('fade');
    if(!noScroll)window.scrollTo(0,0);
    switch(S.view){
      case 'anime':    renderDetail(S.id);break;
      case 'watch':    renderWatch(S.id,S.ep,S.lang);break;
      case 'search':   renderSearch(S.q);break;
      case 'trending': renderList('trending');break;
      case 'movies':   renderList('movies');break;
      case 'schedule': renderSchedule();break;
      case 'mylist':   renderMyList();break;
      case 'community':renderCommunity();break;
      case 'updated':  renderList('updated');break;
      case 'browse':   renderBrowse();break;
      case 'home':     renderHome();break;
      case 'landing':  renderLanding();break;
      default:         renderHome();
    }
  },140);
}

/* ─── HOME ─── */
function renderHome(){
  pbStart();
  var app=document.getElementById('app');app.innerHTML=spin();
  var airingList=[],movieList=[],updatedList=[];
  var recentList=[];
  alQuery(Q_LIST(),{page:1,perPage:18,sort:['TRENDING_DESC'],status:'RELEASING'}).then(function(d){
    airingList=(d&&d.Page&&d.Page.media)||[];
    return alQuery(Q_LIST(),{page:1,perPage:12,sort:['POPULARITY_DESC'],format:'MOVIE'});
  }).then(function(d){
    movieList=(d&&d.Page&&d.Page.media)||[];
    return alQuery(Q_LIST(),{page:1,perPage:18,sort:['UPDATED_AT_DESC'],status:'RELEASING'});
  }).then(function(d){
    updatedList=(d&&d.Page&&d.Page.media)||[];
    /* Fetch recently aired episodes from Jikan */
    return fetch('https://api.jikan.moe/v4/watch/episodes/recent')
      .then(function(r){return r.ok?r.json():Promise.resolve({data:[]});})
      .catch(function(){return {data:[]};});
  }).then(function(d){
    recentList=(d&&d.data)||[];
    app.innerHTML='';
    buildHero(airingList);
    /* Latest Released Episodes (horizontal episode cards) */
    if(recentList.length){var rs=makeRecentSection(recentList);if(rs)app.appendChild(rs);}
    /* Recently Updated — full anime grid */
    if(updatedList.length)app.appendChild(makeSection('Recently Updated','updated',updatedList,'ug'));
    app.appendChild(makeSection('Top Airing','trending',airingList,'ag'));
    if(movieList.length)app.appendChild(makeSection('Popular Movies','movies',movieList,'mg'));
    var cw=getCW();
    if(cw.length){app.appendChild(makeHSection('Continue Watching',cw,cwCard));}
    var rv=lsGet(STORE.RV)||[];
    if(rv.length){app.appendChild(makeHSection('Recently Viewed',rv,rvCard));}
    pbDone();
  }).catch(function(e){app.innerHTML=emptyHTML('Failed to Load',esc(e.message),'error'+'<br><a href="#" onclick="go(\'home\');return false">Retry</a>');pbDone();});
}
function makeRecentSection(list){
  var sec=document.createElement('div');sec.className='sec';
  sec.innerHTML='<div class="sec-hdr"><h2 class="sec-title">Latest Episodes</h2></div>';
  var outer=document.createElement('div');outer.className='hscroll-outer';
  var row=document.createElement('div');row.className='hscroll';
  /* Jikan /watch/episodes/recent structure:
     { entry:{mal_id,title,images}, episodes:[{mal_id,title,episode_id,images,premium}] } */
  list.forEach(function(item){
    if(!item||!item.entry)return;
    var entry=item.entry;
    var eps=item.episodes||[];
    /* Show each released episode as its own card (up to 2 per anime) */
    var shown=0;
    eps.forEach(function(ep){
      if(shown>=2)return;
      if(ep.premium)return; /* skip premium-only */
      shown++;
      var epNum=ep.mal_id||'?';
      var epTitle=ep.title||('Episode '+epNum);
      /* Use episode thumbnail if available, else anime cover */
      var img=(ep.images&&ep.images.jpg&&ep.images.jpg.image_url)||
              (entry.images&&entry.images.jpg&&entry.images.jpg.image_url)||'';
      var animeTitle=entry.title||'Unknown';
      var animeId=entry.mal_id;
      var c=document.createElement('div');c.className='hcard';c.style.width='130px';
      c.innerHTML=
        '<div class="ep-badge">EP '+esc(String(epNum))+'</div>'+
        '<img src="'+esc(img)+'" alt="'+esc(animeTitle)+'" loading="lazy" '+
          'style="width:130px;height:80px;object-fit:cover;display:block" '+
          'onerror="this.src=\'https://placehold.co/130x80/0d0d15/555577?text=N/A\'"/>'+
        '<div class="hcard-info">'+
          '<div class="hcard-title">'+esc(animeTitle)+'</div>'+
          '<div class="hcard-sub" style="white-space:normal;line-height:1.3">'+esc(epTitle)+'</div>'+
        '</div>';
      c.addEventListener('click',function(){
        go('watch',{id:animeId,name:animeTitle,titleAlt:animeTitle,ep:+epNum,lang:S.lang});
      });
      row.appendChild(c);
    });
  });
  if(!row.children.length){return null;}
  outer.appendChild(row);sec.appendChild(outer);
  return sec;
}
function cwCard(item){
  var c=document.createElement('div');c.className='hcard';
  c.innerHTML=skelImg(item.poster,item.title,'',108,152)+'<div class="hcard-info"><div class="hcard-title">'+esc(item.title)+'</div><div class="hcard-sub">EP '+item.ep+' \u2022 '+item.lang.toUpperCase()+'</div></div>';
  c.addEventListener('click',function(){go('watch',{id:item.id,name:item.title,titleAlt:item.titleAlt,ep:item.ep,lang:item.lang});});
  return c;
}
function rvCard(item){
  var c=document.createElement('div');c.className='hcard';
  c.innerHTML=skelImg(item.poster,item.title,'',108,152)+'<div class="hcard-info"><div class="hcard-title">'+esc(item.title)+'</div></div>';
  c.addEventListener('click',function(){go('anime',{id:item.id,name:item.title,titleAlt:item.titleAlt||item.title});});
  return c;
}

/* ─── Hero ─── */
function buildHero(list){
  _heroList=list.slice(0,8);_heroIdx=0;
  var el=document.createElement('div');el.className='hero';
  el.innerHTML='<div class="hero-bg" id="hbg"></div><div class="hero-grad"></div>'+
    '<div class="hero-cnt"><div class="hero-badge">Spotlight</div>'+
    '<h1 class="hero-title" id="htitle"></h1><p class="hero-desc" id="hdesc"></p>'+
    '<div class="hero-btns"><button class="bp" id="hwb">&#9654; Watch Now</button><button class="bs" id="hib">Info</button></div></div>';
  document.getElementById('app').insertBefore(el,document.getElementById('app').querySelector('.sec'));
  setHero(0);clearInterval(_heroTick);
  _heroTick=setInterval(function(){_heroIdx=(_heroIdx+1)%_heroList.length;setHero(_heroIdx);},6000);
}
function setHero(i){
  var m=_heroList[i];if(!m)return;
  var title=alTitle(m),titleAlt=alTitleAlt(m);
  var desc=(m.description||'').replace(/<[^>]+>/g,'').replace(/\[Written[^\]]*\]/g,'').trim();
  var bg=m.bannerImage||alImg(m,'extraLarge');
  document.getElementById('hbg').style.backgroundImage='url('+esc(bg)+')';
  document.getElementById('htitle').textContent=title;
  document.getElementById('hdesc').textContent=desc.length>200?desc.slice(0,200)+'...':desc;
  document.getElementById('hwb').onclick=function(){go('watch',{id:m.id,name:title,titleAlt:titleAlt,ep:1,lang:S.lang});};
  document.getElementById('hib').onclick=function(){go('anime',{id:m.id,name:title,titleAlt:titleAlt});};
}

/* ─── LIST (trending / movies) ─── */
function renderList(type){
  pbStart();
  var app=document.getElementById('app');app.innerHTML='';
  var label=type==='movies'?'Top Anime Movies':type==='updated'?'Recently Updated':'Trending Anime';
  var sec=document.createElement('div');sec.className='sec';sec.style.paddingTop='22px';
  sec.innerHTML='<div class="sec-hdr"><h2 class="sec-title">'+esc(label)+'</h2></div><div class="grid" id="lg"></div>';
  app.appendChild(sec);
  var g=document.getElementById('lg');addSkels(g,12);

  function fetchPage(page){
    var opts={page:page};
    if(type==='movies'){opts.format='MOVIE';opts.sort='POPULARITY_DESC';}
    else if(type==='updated'){opts.sort='UPDATED_AT_DESC';opts.status='RELEASING';}
    else{opts.sort='TRENDING_DESC';}
    return alQuery(Q_LIST(),buildVars(opts)).then(function(d){return(d&&d.Page&&d.Page.media)||[];});
  }

  fetchPage(1).then(function(list){
    g.innerHTML='';
    if(!list.length){g.innerHTML=emptyHTML('Nothing Found','Try different filters or browse another genre.','empty');pbDone();return;}
    appendCards(g,list);pbDone();
    initIO('lg',fetchPage);
  }).catch(function(e){app.innerHTML=emptyHTML('Something Went Wrong',esc(e.message),'error');pbDone();});
}

/* ─── SEARCH ─── */
function renderSearch(q){
  if(!q&&!hasFilters()){go('home');return;}
  pbStart();
  var app=document.getElementById('app');app.innerHTML='';
  var hdr=document.createElement('div');hdr.className='srh-hdr';
  hdr.innerHTML='<div class="srh-title">Results for <span>"'+esc(q||'filtered')+'"</span></div>';
  app.appendChild(hdr);
  var sec=document.createElement('div');sec.className='sec';
  sec.innerHTML='<div class="grid" id="sg"></div>';
  app.appendChild(sec);
  var g=document.getElementById('sg');addSkels(g,12);

  function fetchPage(page){
    return alQuery(Q_LIST(),buildVars({q:q,page:page})).then(function(d){return(d&&d.Page&&d.Page.media)||[];});
  }

  fetchPage(1).then(function(list){
    g.innerHTML='';
    if(!list.length){g.innerHTML=emptyHTML('No Results','Try a different name or adjust filters.','search');pbDone();return;}
    appendCards(g,list);pbDone();
    buildGenreRow(sec,function(){renderSearch(q);});
    initIO('sg',fetchPage);
  }).catch(function(e){app.innerHTML=emptyHTML('Search Failed',esc(e.message),'error');pbDone();});
}

/* ─── SCHEDULE ─── */
function renderBrowse(){
  pbStart();
  var app=document.getElementById('app');
  var SEASONS=[
    {label:'Winter 2025',season:'WINTER',year:2025},
    {label:'Spring 2025',season:'SPRING',year:2025},
    {label:'Summer 2025',season:'SUMMER',year:2025},
    {label:'Fall 2025',season:'FALL',year:2025},
    {label:'Winter 2026',season:'WINTER',year:2026},
    {label:'Spring 2026',season:'SPRING',year:2026},
  ];
  var GENRES=['Action','Adventure','Comedy','Drama','Ecchi','Fantasy','Horror',
    'Mahou Shoujo','Mecha','Music','Mystery','Psychological','Romance',
    'Sci-Fi','Slice of Life','Sports','Supernatural','Thriller'];
  var FORMAT_TABS=[
    {label:'All',val:''},
    {label:'TV',val:'TV'},
    {label:'Movie',val:'MOVIE'},
    {label:'OVA',val:'OVA'},
    {label:'ONA',val:'ONA'},
    {label:'Special',val:'SPECIAL'},
  ];
  var _selGenre='',_selSeason=null,_selYear=null,_selFormat='',_brPage=1,_brLoading=false,_brHasMore=true;

  function buildBrowseHTML(){
    return '<div class="browse-page">'+
      '<h2 class="sec-title" style="margin-bottom:16px">Browse Anime</h2>'+
      /* Season pills */
      '<div class="browse-section-label">Season</div>'+
      '<div class="browse-pills" id="br-seasons">'+
        '<button class="br-pill'+ (!_selSeason?' active':'')+'" data-s="" data-y="">All Seasons</button>'+
        SEASONS.map(function(s){
          var active=(_selSeason===s.season&&_selYear===s.year)?' active':'';
          return '<button class="br-pill'+active+'" data-s="'+s.season+'" data-y="'+s.year+'">'+s.label+'</button>';
        }).join('')+
      '</div>'+
      /* Genre pills */
      '<div class="browse-section-label" style="margin-top:16px">Genre</div>'+
      '<div class="browse-pills" id="br-genres">'+
        '<button class="br-pill'+(!_selGenre?' active':'')+'" data-g="">All Genres</button>'+
        GENRES.map(function(g){
          return '<button class="br-pill'+(_selGenre===g?' active':'')+'" data-g="'+g+'">'+g+'</button>';
        }).join('')+
      '</div>'+
      /* Format tabs */
      '<div class="browse-section-label" style="margin-top:16px">Format</div>'+
      '<div class="browse-pills" id="br-formats">'+
        FORMAT_TABS.map(function(f){
          return '<button class="br-pill'+(_selFormat===f.val?' active':'')+'" data-f="'+f.val+'">'+f.label+'</button>';
        }).join('')+
      '</div>'+
      '<div class="grid" id="br-grid" style="margin-top:20px"></div>'+
      '<div id="br-load-more" style="text-align:center;padding:20px 0;display:none">'+
        '<button class="bs" id="br-more-btn">Load More</button>'+
      '</div>'+
    '</div>';
  }

  function fetchBrowsePage(page){
    _brLoading=true;
    var vars={page:page,perPage:24,sort:['POPULARITY_DESC']};
    if(_selGenre)vars.genre_in=[_selGenre];
    if(_selSeason)vars.season=_selSeason;
    if(_selYear)vars.seasonYear=_selYear;
    if(_selFormat)vars.format=_selFormat;
    return alQuery(Q_LIST(),cleanVars(vars)).then(function(d){
      _brLoading=false;
      var media=(d&&d.Page&&d.Page.media)||[];
      var hasNext=d&&d.Page&&d.Page.pageInfo&&d.Page.pageInfo.hasNextPage;
      _brHasMore=!!hasNext;
      return media;
    }).catch(function(){_brLoading=false;return[];});
  }

  function renderBrowseGrid(media,append){
    var grid=document.getElementById('br-grid');if(!grid)return;
    if(!append)grid.innerHTML='';
    if(!media.length&&!append){grid.innerHTML='<p style="color:var(--dim);padding:20px">No results found.</p>';return;}
    media.forEach(function(m){grid.appendChild(makeCard(m));});
    var lm=document.getElementById('br-load-more');
    if(lm)lm.style.display=_brHasMore?'block':'none';
  }

  function attachBrowseEvents(){
    /* Season pills */
    document.querySelectorAll('#br-seasons .br-pill').forEach(function(btn){
      btn.addEventListener('click',function(){
        document.querySelectorAll('#br-seasons .br-pill').forEach(function(b){b.classList.remove('active');});
        btn.classList.add('active');
        _selSeason=btn.dataset.s||null;
        _selYear=btn.dataset.y?+btn.dataset.y:null;
        _brPage=1;_brHasMore=true;
        fetchBrowsePage(1).then(function(m){renderBrowseGrid(m,false);});
      });
    });
    /* Genre pills */
    document.querySelectorAll('#br-genres .br-pill').forEach(function(btn){
      btn.addEventListener('click',function(){
        document.querySelectorAll('#br-genres .br-pill').forEach(function(b){b.classList.remove('active');});
        btn.classList.add('active');
        _selGenre=btn.dataset.g||'';
        _brPage=1;_brHasMore=true;
        fetchBrowsePage(1).then(function(m){renderBrowseGrid(m,false);});
      });
    });
    /* Format pills */
    document.querySelectorAll('#br-formats .br-pill').forEach(function(btn){
      btn.addEventListener('click',function(){
        document.querySelectorAll('#br-formats .br-pill').forEach(function(b){b.classList.remove('active');});
        btn.classList.add('active');
        _selFormat=btn.dataset.f||'';
        _brPage=1;_brHasMore=true;
        fetchBrowsePage(1).then(function(m){renderBrowseGrid(m,false);});
      });
    });
    /* Load more */
    var moreBtn=document.getElementById('br-more-btn');
    if(moreBtn)moreBtn.addEventListener('click',function(){
      if(_brLoading||!_brHasMore)return;
      _brPage++;
      fetchBrowsePage(_brPage).then(function(m){renderBrowseGrid(m,true);});
    });
  }

  app.innerHTML='<div id="app-inner">'+buildBrowseHTML()+'</div>';
  attachBrowseEvents();
  fetchBrowsePage(1).then(function(m){
    renderBrowseGrid(m,false);
    pbDone();
  });
}

