          '<h2 class="lnd-about-h">Frequently Asked Questions</h2>'+
          '<div class="lnd-faq-list">'+
            ['Is anidexz completely free?|Yes, anidexz is 100% free. No subscription, no registration, no payment. Just open and watch.',
             'Do I need an account?|No account needed. Watch history and My List are saved locally on your device.',
             'Does anidexz have dubbed anime?|Yes! Use the SUB / DUB toggle on any watch page to switch instantly.',
             'How often are episodes updated?|New episodes added daily, within hours of Japan broadcast.',
             'What quality is available?|Up to 1080p HD, auto-adjusts to your connection speed.',
             'Does it work on mobile?|Yes, fully responsive on phones, tablets, and desktops.'].map(function(s){
              var p=s.split('|');
              return '<div class="lnd-faq-item"><div class="lnd-faq-q"><span>'+p[0]+'</span><svg class="lnd-faq-arr" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg></div><div class="lnd-faq-a">'+p[1]+'</div></div>';
            }).join('')+
          '</div>'+
        '</div>'+
      '</div>'+
    '</div>';

  function _on(id,ev,fn){var el=document.getElementById(id);if(el)el.addEventListener(ev,fn);}
  _on('lnd-home','click',function(){go('home');});
  _on('lnd-movies','click',function(){go('movies');});
  _on('lnd-tvseries','click',function(){go('trending');});
  _on('lnd-popular','click',function(){go('trending');});
  _on('lnd-airing','click',function(){go('trending');});
  _on('lnd-community','click',function(){go('community');});
  _on('lnd-watch','click',function(){go('home');});
  _on('lnd-sbtn','click',function(){var i=document.getElementById('lnd-inp');if(i&&i.value.trim())go('search',{q:i.value.trim()});});
  _on('lnd-inp','keydown',function(e){if(e.key==='Enter'&&this.value.trim())go('search',{q:this.value.trim()});});
  document.querySelectorAll('.lnd-ts').forEach(function(b){b.addEventListener('click',function(){go('search',{q:b.dataset.q});});});

  /* img is inline in HTML */

    document.querySelectorAll('.lnd-faq-item').forEach(function(item){
    item.querySelector('.lnd-faq-q').addEventListener('click',function(){
      var isOpen=item.classList.contains('open');
      document.querySelectorAll('.lnd-faq-item').forEach(function(x){x.classList.remove('open');});
      if(!isOpen)item.classList.add('open');
    });
  });
  pbDone();
}

function renderSchedule(){
  pbStart();
  var app=document.getElementById('app');app.innerHTML=spin();
  var days=['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  var seasons=['WINTER','SPRING','SUMMER','FALL'];
  var now=new Date(),dow=now.getDay(),mo=now.getMonth();
  var seasonMap=[0,0,0,1,1,1,2,2,2,3,3,3];
  var curSeason=seasons[seasonMap[mo]];
  var curYear=now.getFullYear();
  alQuery(Q_LIST(),{page:1,perPage:30,sort:['TRENDING_DESC'],status:'RELEASING',season:curSeason,seasonYear:curYear}).then(function(d){
    var list=(d&&d.Page&&d.Page.media)||[];
    app.innerHTML='<div class="sec" style="padding-top:22px"><div class="sec-hdr"><h2 class="sec-title">Airing This Season \u2014 '+esc(days[dow])+', '+curSeason.charAt(0)+curSeason.slice(1).toLowerCase()+' '+curYear+'</h2></div><div class="grid" id="schg"></div></div>';
    var g=document.getElementById('schg');
    if(!list.length)g.innerHTML=emptyHTML('No schedule data','Nothing found for this season.');
    else appendCards(g,list);
    pbDone();
  }).catch(function(e){app.innerHTML=emptyHTML('Failed',esc(e.message));pbDone();});
}

/* ─── MY LIST ─── */
function renderMyList(){
  var app=document.getElementById('app');app.innerHTML='';
  var wl=getWL();
  var sec=document.createElement('div');sec.className='sec';sec.style.paddingTop='22px';
  sec.innerHTML='<div class="sec-hdr"><h2 class="sec-title">My List</h2><span style="font-size:11px;color:var(--dim)">'+wl.length+' titles</span></div><div class="grid" id="wlg"></div>';
  app.appendChild(sec);
  var g=document.getElementById('wlg');
  if(!wl.length){g.innerHTML=emptyHTML('Your list is empty','Add anime by clicking the \u2665 on any card.<br><a href="#" onclick="go(\'browse\');return false">Browse Anime</a>');return;}
  wl.forEach(function(item,i){
    var fakeM={id:item.id,title:{english:item.title,romaji:item.titleAlt||item.title},coverImage:{large:item.poster||'',medium:item.poster||''},averageScore:item.score,format:(item.type||'').replace(/ /g,'_')};
    g.appendChild(makeCard(fakeM,i*34));
  });
}

/* ─── DETAIL ─── */
function renderDetail(id){
  if(!id){go('home');return;}
  pbStart();
  var app=document.getElementById('app');app.innerHTML=spin();
  alQuery(Q_DETAIL(),{id:id}).then(function(d){
    var m=d&&d.Media;if(!m)throw new Error('Not found');
    var title=alTitle(m),titleAlt=alTitleAlt(m);
    S.name=title;S.titleAlt=titleAlt;
    var poster=alImg(m,'extraLarge');
    var banner=m.bannerImage||poster;
    addRV(id,title,titleAlt,poster);
    /* Update OG meta for social sharing */
    (function(){
      var ogT=document.getElementById('og-title'),ogD=document.getElementById('og-desc'),ogI=document.getElementById('og-img'),ogU=document.getElementById('og-url');
      var twT=document.getElementById('tw-title'),twD=document.getElementById('tw-desc'),twI=document.getElementById('tw-img');
      var shareUrl=location.origin+location.pathname+'?v=anime&id='+id;
      if(ogT)ogT.content=title+' - anidexz';
      if(twT)twT.content=title+' - anidexz';
      if(ogU)ogU.content=shareUrl;
    })();
    var score=scoreDisp(m);
    var wl=isWL(id);
    /* Update OG image with anime poster */
    (function(){
      var ogI=document.getElementById('og-img'),twI=document.getElementById('tw-img');
      var ogD=document.getElementById('og-desc'),twD=document.getElementById('tw-desc');
      var img=alImg(m,'extraLarge')||alImg(m,'large')||'';
      var desc=(m.description||'').replace(/<[^>]+>/g,'').replace(/\[Written[^\]]*\]/g,'').trim().slice(0,160);
      if(ogI)ogI.content=img;if(twI)twI.content=img;
      if(ogD&&desc)ogD.content=desc;if(twD&&desc)twD.content=desc;
    })();
    var syn=(m.description||'No synopsis.').replace(/<br\s*\/?>/gi,'\n').replace(/<[^>]+>/g,'').replace(/\[Written[^\]]*\]/g,'').trim();
    var genres=m.genres||[];
    var studios=(m.studios&&m.studios.nodes)||[];
    var chars=(m.characters&&m.characters.edges)||[];
    var staff=(m.staff&&m.staff.edges)||[];
    var relations=(m.relations&&m.relations.edges)||[];
    var recs=(m.recommendations&&m.recommendations.nodes)||[];
    var trailer=m.trailer;
    var tags=(m.tags||[]).filter(function(t){return!t.isMediaSpoiler&&t.rank>=70;}).slice(0,8);
    var ep=m.episodes||0;

    /* Status text */
    var statusMap={FINISHED:'Completed',RELEASING:'Airing',NOT_YET_RELEASED:'Upcoming',CANCELLED:'Cancelled',HIATUS:'Hiatus'};
    var statusDisp=statusMap[m.status]||m.status||'';

    app.innerHTML=
      '<div class="dhero">'+
        '<div class="dhero-bg" style="background-image:url('+esc(banner)+')"></div>'+
        '<div class="dhero-grad"></div>'+
        '<div class="dhero-cnt">'+
          '<img class="dposter" src="'+esc(poster)+'" alt="'+esc(title)+'" loading="lazy" onerror="this.src=\'https://placehold.co/120x180/0d0d15/555577?text=N/A\'"/>'+
          '<div class="dinfo">'+
            '<h1 class="dtitle">'+esc(title)+'</h1>'+
            (m.title.native?'<div class="dnative">'+esc(m.title.native)+'</div>':'')+
            (titleAlt&&titleAlt!==title?'<div class="dnative" style="font-size:12px;color:var(--dim);margin-bottom:8px">'+esc(titleAlt)+'</div>':'')+
            '<div class="dmeta">'+
              (score&&score!=='N/A'?'<span class="chip sc">&#9733; '+score+'</span>':'')+
              (ep?'<span class="chip">'+ep+' eps</span>':'')+
              (statusDisp?'<span class="chip">'+esc(statusDisp)+'</span>':'')+
              (m.seasonYear?'<span class="chip">'+m.seasonYear+'</span>':'')+
              (m.format?'<span class="chip">'+esc(fmtFormat(m.format))+'</span>':'')+
              (m.duration?'<span class="chip">'+m.duration+' min</span>':'')+
              (m.source?'<span class="chip">'+esc(m.source.replace(/_/g,' '))+'</span>':'')+
            '</div>'+
            '<div style="display:flex;gap:8px;flex-wrap:wrap">'+
              '<button class="bp" id="d-watch">&#9654; Watch Now</button>'+
              '<button class="bs" id="d-wl" style="gap:5px">'+heartSVG(wl)+' '+(wl?'In My List':'My List')+'</button>'+
            '</div>'+
          '</div>'+
        '</div>'+
      '</div>'+
      '<div class="dbody" id="dbody"></div>';

    /* Buttons */
    document.getElementById('d-watch').addEventListener('click',function(){go('watch',{id:id,name:title,titleAlt:titleAlt,ep:1,lang:S.lang});});
    var dlWl=document.getElementById('d-wl');
    dlWl.addEventListener('click',function(){
      var added=toggleWL({id:id,title:title,titleAlt:titleAlt,poster:poster,score:score,type:fmtFormat(m.format)});
      dlWl.innerHTML=heartSVG(added)+' '+(added?'In My List':'My List');
      toast(added?'Added to My List':'Removed from My List');
    });
    /* Share button */
    var dshr=document.getElementById('d-share');
    if(dshr)dshr.addEventListener('click',function(){
      var shareUrl=location.origin+location.pathname+'?v=anime&id='+id;
      var shareData={title:title,text:'Check out '+title+' on anidexz',url:shareUrl};
      if(navigator.share&&navigator.canShare&&navigator.canShare(shareData)){
        navigator.share(shareData).catch(function(){});
      } else {
        navigator.clipboard.writeText(shareUrl).then(function(){
          toast('Link copied to clipboard!');
        }).catch(function(){
          prompt('Copy this link:',shareUrl);
        });
      }
    });

    var dbody=document.getElementById('dbody');

    /* Synopsis */
    var synEl=document.createElement('p');synEl.className='dsynopsis';synEl.textContent=syn;dbody.appendChild(synEl);

    /* Stats grid */
    var statsHtml='<div class="stats-grid">';
    if(score&&score!=='N/A')statsHtml+='<div class="stat-box"><div class="stat-val">'+score+'</div><div class="stat-lbl">Score</div></div>';
    if(m.popularity)statsHtml+='<div class="stat-box"><div class="stat-val">'+fmtNum(m.popularity)+'</div><div class="stat-lbl">Popularity</div></div>';
    if(m.favourites)statsHtml+='<div class="stat-box"><div class="stat-val">'+fmtNum(m.favourites)+'</div><div class="stat-lbl">Favourites</div></div>';
    if(m.trending)statsHtml+='<div class="stat-box"><div class="stat-val">'+m.trending+'</div><div class="stat-lbl">Trending</div></div>';
    statsHtml+='</div>';
    dbody.insertAdjacentHTML('beforeend',statsHtml);

        /* Genres */
    if(genres.length){
      var gWrap=document.createElement('div');gWrap.className='genres';
      genres.forEach(function(g){var t=document.createElement('span');t.className='gtag';t.textContent=g;t.addEventListener('click',function(){_filter.genre=g;go('search',{q:''},false);});gWrap.appendChild(t);});
      dbody.appendChild(gWrap);
    }

    /* Studios */
    if(studios.length){
      var stSec=document.createElement('div');stSec.style.marginBottom='18px';
      stSec.innerHTML='<div class="sec-hdr" style="margin-bottom:8px"><h3 class="sec-title" style="font-size:15px">Studios</h3></div>';
      var stRow=document.createElement('div');stRow.style.display='flex';stRow.style.flexWrap='wrap';
      studios.forEach(function(st){
        var t=document.createElement('span');t.className='studio-tag';t.textContent=st.name;
        t.addEventListener('click',function(){go('search',{q:st.name});});
        stRow.appendChild(t);
      });
      stSec.appendChild(stRow);dbody.appendChild(stSec);
    }

    /* Tags */
    if(tags.length){
      var tagSec=document.createElement('div');tagSec.style.marginBottom='20px';
      tagSec.innerHTML='<div class="sec-hdr" style="margin-bottom:8px"><h3 class="sec-title" style="font-size:15px">Tags</h3></div><div style="display:flex;flex-wrap:wrap;gap:5px">'+
        tags.map(function(t){return'<span style="background:var(--glass);border:1px solid var(--bdr);border-radius:14px;padding:3px 10px;font-size:10px;font-weight:700;color:var(--dim)">'+esc(t.name)+'<span style="color:var(--acc2);margin-left:4px">'+t.rank+'%</span></span>';}).join('')+
      '</div>';
      dbody.appendChild(tagSec);
    }

    /* Next Episode Countdown */
    if(m.nextAiringEpisode&&m.nextAiringEpisode.airingAt){
      var nep=m.nextAiringEpisode;
      var cdDiv=document.createElement('div');cdDiv.className='countdown-box';
      cdDiv.innerHTML=
        '<div class="countdown-icon">'+
          '<svg width="16" height="16" fill="none" stroke="#fff" stroke-width="2" viewBox="0 0 24 24">'+
            '<circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>'+
          '</svg>'+
        '</div>'+
        '<div style="flex:1;min-width:0">'+
          '<div class="countdown-label">Next Episode</div>'+
          '<div class="countdown-ep">Episode '+nep.episode+' airing in</div>'+
          '<div class="countdown-timer" id="cd-timer">'+
            '<div class="cd-unit"><span class="cd-val" id="cd-d">--</span><div class="cd-lbl">Days</div></div>'+
            '<div class="cd-sep">:</div>'+
            '<div class="cd-unit"><span class="cd-val" id="cd-h">--</span><div class="cd-lbl">Hours</div></div>'+
            '<div class="cd-sep">:</div>'+
            '<div class="cd-unit"><span class="cd-val" id="cd-m">--</span><div class="cd-lbl">Mins</div></div>'+
            '<div class="cd-sep">:</div>'+
            '<div class="cd-unit"><span class="cd-val" id="cd-s">--</span><div class="cd-lbl">Secs</div></div>'+
          '</div>'+
        '</div>';
      dbody.appendChild(cdDiv);
      /* Start countdown ticker */
      var _cdTarget=nep.airingAt*1000;
      var _cdInterval=setInterval(function(){
        var now=Date.now();
        var diff=_cdTarget-now;
        var cdD=document.getElementById('cd-d');
        var cdH=document.getElementById('cd-h');
        var cdM=document.getElementById('cd-m');
        var cdS=document.getElementById('cd-s');
        if(!cdD){clearInterval(_cdInterval);return;}
        if(diff<=0){
          cdD.textContent=cdH.textContent=cdM.textContent='00';
          cdS.textContent='00';
          clearInterval(_cdInterval);
          return;
        }
        var days=Math.floor(diff/(1000*60*60*24));
        var hours=Math.floor((diff%(1000*60*60*24))/(1000*60*60));
        var mins=Math.floor((diff%(1000*60*60))/(1000*60));
        var secs=Math.floor((diff%(1000*60))/1000);
        cdD.textContent=String(days).padStart(2,'0');
        cdH.textContent=String(hours).padStart(2,'0');
        cdM.textContent=String(mins).padStart(2,'0');
        cdS.textContent=String(secs).padStart(2,'0');
      },1000);
    }


    /* Tab bar */
    var tabs=[
      {id:'tab-eps',label:'Episodes'},
      {id:'tab-chars',label:'Characters'},
      {id:'tab-staff',label:'Staff'},
      {id:'tab-rel',label:'Relations'}
    ];
    if(trailer&&trailer.id)tabs.push({id:'tab-trailer',label:'Trailer'});
    if(recs.length)tabs.push({id:'tab-recs',label:'Recommended'});

    var tabBar=document.createElement('div');tabBar.className='tab-bar';
    var panels={};
    tabs.forEach(function(t,i){
      var btn=document.createElement('button');btn.className='tab-btn'+(i===0?' on':'');btn.textContent=t.label;btn.dataset.tab=t.id;
      btn.addEventListener('click',function(){
        tabBar.querySelectorAll('.tab-btn').forEach(function(b){b.classList.remove('on');});
        btn.classList.add('on');
        Object.keys(panels).forEach(function(k){panels[k].classList.remove('on');});
        panels[t.id].classList.add('on');
      });
      tabBar.appendChild(btn);
      var panel=document.createElement('div');panel.className='tab-panel'+(i===0?' on':'');panel.id=t.id;
      panels[t.id]=panel;
    });
    dbody.appendChild(tabBar);
    tabs.forEach(function(t){dbody.appendChild(panels[t.id]);});

    /* Episodes panel */
    var epPanel=panels['tab-eps'];
    epPanel.innerHTML='<div class="ep-hdr"><h3 class="ep-hdr-title">Episodes</h3>'+
      '<div class="ltog"><button class="lbtn on" data-l="sub">SUB</button><button class="lbtn" data-l="dub">DUB</button></div></div>'+
      '<div id="epwrap">'+spin()+'</div>';
    epPanel.querySelectorAll('.lbtn').forEach(function(b){b.addEventListener('click',function(){epPanel.querySelectorAll('.lbtn').forEach(function(x){x.classList.remove('on');});this.classList.add('on');S.lang=this.dataset.l;});});

    /* Characters panel */
    var charPanel=panels['tab-chars'];
    if(chars.length){
      var charContent='<div style="margin-bottom:12px"><h3 class="ep-hdr-title">Characters &amp; Voice Actors</h3></div>';
      /* Group: character + VA rows */
      charContent+='<div class="va-row">';
      chars.forEach(function(edge){
        var ch=edge.node;var va=edge.voiceActors&&edge.voiceActors[0];
        var chImg=ch.image&&(ch.image.large||ch.image.medium)||'';
        var vaImg=va&&va.image&&(va.image.large||va.image.medium)||'';
        charContent+='<div class="va-item">'+
          '<img src="'+esc(chImg)+'" alt="'+esc(ch.name.full)+'" onerror="this.src=\'https://placehold.co/44x44/0d0d15/555577?text=?\'" loading="lazy"/>'+
          '<div class="va-info">'+
            '<div class="va-name">'+esc(ch.name.full)+'</div>'+
            (ch.name.native?'<div class="va-sub">'+esc(ch.name.native)+'</div>':'')+
          '</div>'+
          '<div class="va-role">'+esc(edge.role||'')+'</div>'+
          (va?
            '<img src="'+esc(vaImg)+'" alt="'+esc(va.name.full)+'" onerror="this.src=\'https://placehold.co/44x44/0d0d15/555577?text=?\'" loading="lazy" style="width:44px;height:44px;object-fit:cover;border-radius:50%;flex-shrink:0;border:1px solid var(--bdr)"/>'+
            '<div class="va-info" style="text-align:right">'+
              '<div class="va-name">'+esc(va.name.full)+'</div>'+
              '<div class="va-sub">JP Voice</div>'+
            '</div>'
          :'')+
        '</div>';
      });
      charContent+='</div>';
      charPanel.innerHTML=charContent;
    }else{charPanel.innerHTML='<p style="color:var(--dim);font-size:13px;padding:12px 0">No character data available.</p>';}

    /* Staff panel */
    var staffPanel=panels['tab-staff'];
    if(staff.length){
      var staffContent='<div style="margin-bottom:12px"><h3 class="ep-hdr-title">Staff</h3></div><div class="va-row">';
      staff.forEach(function(edge){
        var st=edge.node;
        var stImg=st.image&&(st.image.large||st.image.medium)||'';
        staffContent+='<div class="va-item">'+
          '<img src="'+esc(stImg)+'" alt="'+esc(st.name.full)+'" onerror="this.src=\'https://placehold.co/44x44/0d0d15/555577?text=?\'" loading="lazy"/>'+
          '<div class="va-info"><div class="va-name">'+esc(st.name.full)+'</div></div>'+
          '<div class="va-role">'+esc(edge.role||'')+'</div>'+
        '</div>';
      });
      staffContent+='</div>';
      staffPanel.innerHTML=staffContent;
    }else{staffPanel.innerHTML='<p style="color:var(--dim);font-size:13px;padding:12px 0">No staff data available.</p>';}

    /* Relations panel */
    var relPanel=panels['tab-rel'];
    if(relations.length){
      var relContent='<div style="margin-bottom:12px"><h3 class="ep-hdr-title">Related</h3></div><div class="rel-grid">';
      relations.forEach(function(edge){
        var rn=edge.node;if(!rn||rn.type!=='ANIME')return;
        var rTitle=alTitle(rn);
        var rImg=rn.coverImage&&rn.coverImage.medium||'';
        relContent+='<div class="rel-card" data-rid="'+rn.id+'" data-rtitle="'+esc(rTitle)+'" data-ralt="'+esc(alTitleAlt(rn))+'">'+
          '<img src="'+esc(rImg)+'" alt="'+esc(rTitle)+'" onerror="this.src=\'https://placehold.co/36x50/0d0d15/555577?text=?\'" loading="lazy"/>'+
          '<div class="rel-info"><div class="rel-type">'+esc(edge.relationType||'')+'</div><div class="rel-title">'+esc(rTitle)+'</div><div class="va-sub">'+esc(fmtFormat(rn.format||''))+'</div></div>'+
        '</div>';
      });
      relContent+='</div>';
      relPanel.innerHTML=relContent;
      relPanel.querySelectorAll('.rel-card').forEach(function(rc){
        rc.addEventListener('click',function(){go('anime',{id:+rc.dataset.rid,name:rc.dataset.rtitle,titleAlt:rc.dataset.ralt});});
      });
    }else{relPanel.innerHTML='<p style="color:var(--dim);font-size:13px;padding:12px 0">No related entries.</p>';}

    /* Trailer panel */
    if(trailer&&trailer.id&&panels['tab-trailer']){
      var tPanel=panels['tab-trailer'];
      var tSrc='';
      if(trailer.site==='youtube')tSrc='https://www.youtube.com/embed/'+trailer.id+'?autoplay=0&rel=0';
      else if(trailer.site==='dailymotion')tSrc='https://www.dailymotion.com/embed/video/'+trailer.id;
      if(tSrc){
        tPanel.innerHTML='<div style="margin-bottom:12px"><h3 class="ep-hdr-title">Trailer</h3></div>'+
          '<div class="trailer-wrap"><iframe src="'+esc(tSrc)+'" allowfullscreen allow="autoplay; encrypted-media" loading="lazy"></iframe></div>';
      }else{tPanel.innerHTML='<p style="color:var(--dim);font-size:13px;padding:12px 0">Trailer not available.</p>';}
    }

    /* Recommendations panel */
    if(recs.length&&panels['tab-recs']){
      var recPanel=panels['tab-recs'];
      recPanel.innerHTML='<div style="margin-bottom:12px"><h3 class="ep-hdr-title">You May Also Like</h3></div>';
      var recOuter=document.createElement('div');recOuter.className='hscroll-outer';
      var recRow=document.createElement('div');recRow.className='hscroll';
      recs.forEach(function(r){
        var rm=r.mediaRecommendation;if(!rm)return;
        var rt=alTitle(rm);
        var c=document.createElement('div');c.className='hcard';
        c.innerHTML=skelImg(rm.coverImage&&(rm.coverImage.large||rm.coverImage.medium),rt,'',108,152)+
          '<div class="hcard-info"><div class="hcard-title">'+esc(rt)+'</div><div class="hcard-sub">'+(rm.averageScore?'&#9733; '+rm.averageScore:'')+'</div></div>';
        c.addEventListener('click',function(){go('anime',{id:rm.id,name:rt,titleAlt:alTitleAlt(rm)});});
        recRow.appendChild(c);
      });
      recOuter.appendChild(recRow);recPanel.appendChild(recOuter);
    }

    pbDone();

    /* Load episodes */
    return loadEpisodes(m.idMal,id);
  }).then(function(epList){
    var wrap=document.getElementById('epwrap');if(!wrap)return;
    if(!epList||!epList.length){wrap.innerHTML='<p style="color:var(--dim);font-size:13px">No episode data.</p>';return;}
    var CHUNK=100;
    function buildEpChunk(eps,activeEp){
      var g=document.createElement('div');g.className='epgrid';
      eps.forEach(function(n){
        var btn=document.createElement('button');
        btn.className='epbtn'+(n===activeEp?' active':'');
        btn.textContent=n;
        btn.addEventListener('click',function(){go('watch',{id:S.id,name:S.name,titleAlt:S.titleAlt,ep:n,lang:S.lang});});
        g.appendChild(btn);
      });
      return g;
    }
    function renderEpSection(startIdx){
      wrap.innerHTML='';
      /* Range selector — only show if more than CHUNK episodes */
      if(epList.length>CHUNK){
        var sel=document.createElement('div');sel.className='ep-range-bar';
        var totalChunks=Math.ceil(epList.length/CHUNK);
        for(var c=0;c<totalChunks;c++){
          var from=c*CHUNK+1,to=Math.min((c+1)*CHUNK,epList.length);
          /* use last ep number in chunk as "to" display */
          var fromEp=epList[c*CHUNK],toEp=epList[Math.min((c+1)*CHUNK,epList.length)-1];
          var rb=document.createElement('button');
          rb.className='ep-range-btn'+(startIdx===c*CHUNK?' active':'');
          rb.textContent='EP '+fromEp+'-'+toEp;
          (function(ci){rb.addEventListener('click',function(){renderEpSection(ci*CHUNK);});})(c);
          sel.appendChild(rb);
        }
        wrap.appendChild(sel);
      }
      var chunk=epList.slice(startIdx,startIdx+CHUNK);
      wrap.appendChild(buildEpChunk(chunk,null));
    }
    renderEpSection(0);
  }).catch(function(e){document.getElementById('app').innerHTML=emptyHTML('Failed',esc(e.message)+'<br><a href="#" onclick="go(\'home\');return false">Go home</a>');pbDone();});
}

function fmtNum(n){if(n>=1000000)return(n/1000000).toFixed(1)+'M';if(n>=1000)return(n/1000).toFixed(1)+'K';return String(n);}

/* ─── Episodes (AniList doesn't provide episode list via free API, build numbered list) ─── */
function loadEpisodes(malId,alId){
  /* Use Jikan which only returns RELEASED episodes */
  var _jikanBase='https://api.jikan.moe/v4';
  if(!malId){
    /* No MAL id - fallback: return empty so watch still works with ep=1 */
    return Promise.resolve([1]);
  }
  function fetchPage(page,acc){
    return fetch(_jikanBase+'/anime/'+malId+'/episodes?page='+page)
      .then(function(r){return r.ok?r.json():Promise.resolve({data:[],pagination:{has_next_page:false}});})
      .catch(function(){return {data:[],pagination:{has_next_page:false}};})
      .then(function(d){
        var eps=(d.data||[]);
        var all=acc.concat(eps);
        if(d.pagination&&d.pagination.has_next_page&&page<5){
          return new Promise(function(res){setTimeout(res,350);}).then(function(){return fetchPage(page+1,all);});
        }
        return all;
      });
  }
  return fetchPage(1,[]).then(function(eps){
    if(!eps.length){
      /* Jikan returned nothing - anime may not be indexed yet, show ep 1 only */
      return [1];
    }
    /* Return only the episode numbers that Jikan confirmed exist */
    return eps.map(function(e){return e.mal_id||e.episode_id||1;});
  });
}

/* ─── WATCH ─── */
function renderWatch(id,ep,lang){
  if(!id||!ep){go('anime',{id:id,name:S.name,titleAlt:S.titleAlt});return;}
  pbStart();
  var app=document.getElementById('app');app.innerHTML=spin();
  lang=lang||'sub';
  alQuery(Q_DETAIL(),{id:id}).then(function(d){
    var m=d&&d.Media;if(!m)throw new Error('Not found');
    S.name=alTitle(m);S.titleAlt=alTitleAlt(m);
    var title=S.name,titleAlt=S.titleAlt,poster=alImg(m);
    var epCount=m.episodes||0;
    return loadEpisodes(m.idMal,id).then(function(eps){return{title:title,titleAlt:titleAlt,poster:poster,eps:eps,maxEp:eps.length};});
  }).then(function(ctx){
    var title=ctx.title,titleAlt=ctx.titleAlt,poster=ctx.poster,eps=ctx.eps,maxEp=ctx.maxEp;
    var stitle=title.length>22?title.slice(0,22)+'...':title;

    app.innerHTML=
      '<div class="wlayout'+(  _theatre?' theatre':'  ')+'" id="wlayout">'+
        '<div style="min-width:0;overflow:hidden">'+
          '<div class="pwrap" id="pwrap"><div class="pload" id="pload">'+spin()+'</div></div>'+
          '<div class="winfo">'+
            '<div class="wt">'+esc(title)+'</div>'+
            '<div class="wet">Episode '+ep+'</div>'+
            '<div class="wnav">'+
              (ep>1?'<button class="bs" id="wprev">&#9664; Prev</button>':'')+
              (maxEp>0&&ep<maxEp?'<button class="bp" id="wnext">Next &#9654;</button>':'')+
              '<button class="wctrl" id="theatre-btn" title="Theatre Mode (T)">'+
                '<svg width="11" height="11" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"/></svg> Theatre'+
              '</button>'+
              '<button class="wctrl'+(  _anEnabled?' on':'')+'" id="an-toggle">'+
                '<svg width="11" height="11" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/><line x1="19" x2="19" y1="3" y2="21"/></svg> Auto-Next'+
              '</button>'+
              '<div class="ltog" style="margin-left:auto">'+
                '<button class="lbtn'+(lang==='sub'?' on':'')+'" data-l="sub">SUB</button>'+
                '<button class="lbtn'+(lang==='dub'?' on':'')+'" data-l="dub">DUB</button>'+
              '</div>'+
            '</div>'+
            '<div class="kb-hint">'+
              '<span><kbd class="kb-key">&#8592;</kbd> Prev ep</span>'+
              '<span><kbd class="kb-key">&#8594;</kbd> Next ep</span>'+
              '<span><kbd class="kb-key">F</kbd> Fullscreen</span>'+
              '<span><kbd class="kb-key">T</kbd> Theatre</span>'+
            '</div>'+
          '</div>'+
        '</div>'+
        '<div class="sbar">'+
          '<div class="sbar-title">'+
            '<img src="'+esc(poster)+'" style="width:26px;height:26px;object-fit:cover;border-radius:4px;flex-shrink:0" loading="lazy" alt=""/>'+
            esc(stitle)+
          '</div>'+
          '<div class="eplist" id="eplist">'+
            eps.map(function(n){
              return'<div class="epli'+(n===ep?' on':'')+'" data-n="'+n+'">'+
                '<div class="epnum">'+n+'</div>'+
                '<span class="epitxt">Episode '+n+'</span>'+
              '</div>';
            }).join('')+
          '</div>'+
        '</div>'+
      '</div>'+
      '<div class="mob-ep-wrap">'+
        '<div class="mob-ep-title">Episodes</div>'+
        '<div class="epgrid" id="mepg"></div>'+
      '</div>';

    /* Sidebar */
    var el=document.getElementById('eplist');
    if(el){
      el.addEventListener('click',function(e){var li=e.target.closest('.epli');if(li)go('watch',{id:id,name:title,titleAlt:titleAlt,ep:+li.dataset.n,lang:S.lang});});
      var active=el.querySelector('.epli.on');if(active)setTimeout(function(){active.scrollIntoView({block:'center'});},60);
    }
    /* Mobile ep grid */
    var mg=document.getElementById('mepg');
    if(mg)eps.forEach(function(n){
      var btn=document.createElement('button');btn.className='epbtn'+(n===ep?' on':'');btn.textContent=n;
      btn.addEventListener('click',function(){go('watch',{id:id,name:title,titleAlt:titleAlt,ep:n,lang:S.lang});});
      mg.appendChild(btn);
    });
    /* Prev/Next */
    var pp=document.getElementById('wprev'),np=document.getElementById('wnext');
    if(pp)pp.addEventListener('click',function(){go('watch',{id:id,name:title,titleAlt:titleAlt,ep:ep-1,lang:S.lang});});
    if(np)np.addEventListener('click',function(){go('watch',{id:id,name:title,titleAlt:titleAlt,ep:ep+1,lang:S.lang});});
    /* Lang toggle */
    document.querySelectorAll('.lbtn').forEach(function(b){
      b.addEventListener('click',function(){document.querySelectorAll('.lbtn').forEach(function(x){x.classList.remove('on');});this.classList.add('on');S.lang=this.dataset.l;_cp.lang=this.dataset.l;reloadPlayer();});
    });
    /* Theatre */
    var tb=document.getElementById('theatre-btn');
    if(tb){if(_theatre){tb.classList.add('on');document.getElementById('wlayout').classList.add('theatre');}tb.addEventListener('click',toggleTheatre);}
    /* Auto-next */
    var ant=document.getElementById('an-toggle');
    if(ant){
      ant.classList.toggle('on',_anEnabled);
      ant.addEventListener('click',function(){_anEnabled=!_anEnabled;ant.classList.toggle('on',_anEnabled);toast(_anEnabled?'Auto-Next: ON':'Auto-Next: OFF');if(_anEnabled)startAN(maxEp);else clearAN();});
    }
    /* Swipe */
    var pwrap=document.getElementById('pwrap');
    if(pwrap){
      var swX=null,swY=null;
      pwrap.addEventListener('touchstart',function(e){if(e.touches.length===1){swX=e.touches[0].clientX;swY=e.touches[0].clientY;}},{passive:true});
      pwrap.addEventListener('touchend',function(e){
        if(swX===null)return;
        var dx=e.changedTouches[0].clientX-swX,dy=e.changedTouches[0].clientY-swY;
        if(Math.abs(dx)>Math.abs(dy)&&Math.abs(dx)>50){
          if(dx<0&&ep<maxEp){go('watch',{id:id,name:title,titleAlt:titleAlt,ep:ep+1,lang:S.lang});toast('Next \u2192');}
          else if(dx>0&&ep>1){go('watch',{id:id,name:title,titleAlt:titleAlt,ep:ep-1,lang:S.lang});toast('\u2190 Prev');}
        }
        swX=null;swY=null;
      },{passive:true});
    }


    pbDone();
    _cp={name:title,titleAlt:titleAlt,ep:ep,lang:lang};
    saveCW(id,ep,lang,title,titleAlt,poster);
    startPlayer();
  }).catch(function(e){document.getElementById('app').innerHTML=emptyHTML('Something Went Wrong',esc(e.message),'error');pbDone();});
}

/* ─── Episode ID / Player resolution ─── */
function toSlug(s){return(s||'').toLowerCase().replace(/[^a-z0-9\s]/g,' ').replace(/\s+/g,'-').replace(/-{2,}/g,'-').replace(/^-|-$/g,'');}
function slugVariants(name,alt){
  var seen={},out=[];
  function add(s){var sl=toSlug(s||'');if(sl.length>1&&!seen[sl]){seen[sl]=1;out.push(sl);}}
  add(name);add(alt);
  add((name||'').replace(/\s*[:]/g,' ').replace(/\s+/g,' ').trim());
  add((alt||'').replace(/\s*[:]/g,' ').replace(/\s+/g,' ').trim());
  add((name||'').replace(/\s*[:\u2013\u2014].*$/,'').trim());
  add((alt||'').replace(/\s*[:\u2013\u2014].*$/,'').trim());
  add((name||'').replace(/\s+(season|part|cour|s)\s*\d+\s*$/i,'').trim());
  add((alt||'').replace(/\s+(season|part|cour|s)\s*\d+\s*$/i,'').trim());
  add((name||'').replace(/\s*\(\d{4}\)\s*$/,'').trim());
  add((name||'').split(/\s+/)[0]);add((alt||'').split(/\s+/)[0]);
  return out;
}
function parseEpResponse(d){
  if(d&&d.contents){try{d=JSON.parse(d.contents);}catch(x){}}
  var id=d&&(d.episode_id||d.episodeId||d.epId||d.id);
  if(id)return String(id);
  throw new Error(d&&d.message?d.message:'Episode not found');
}
function fetchDirect(slug,ep){return fetch(_b+'?name='+slug+'&episode='+ep,{cache:'no-store'}).then(function(r){if(!r.ok)throw new Error('HTTP '+r.status);return r.json();}).then(parseEpResponse);}
function fetchViaProxy(slug,ep,base){return fetch(base+encodeURIComponent(_b+'?name='+slug+'&episode='+ep),{cache:'no-store'}).then(function(r){if(!r.ok)throw new Error('HTTP '+r.status);return r.json();}).then(parseEpResponse);}
function fetchEpId(slug,ep){return fetchDirect(slug,ep).catch(function(){return fetchViaProxy(slug,ep,'https://api.allorigins.win/raw?url=');}).catch(function(){return fetchViaProxy(slug,ep,'https://corsproxy.io/?');});}
function resolveEpId(name,alt,ep){
  var variants=slugVariants(name,alt),i=0;
  function next(){if(i>=variants.length)return Promise.reject(new Error('Episode not available'));var v=variants[i++];return fetchEpId(v,ep).catch(function(){return next();});}
  return next();
}
function startPlayer(){
  var wrap=document.getElementById('pwrap');if(!wrap)return;
  var sEp=_cp.ep,sLang=_cp.lang,sName=_cp.name,sAlt=_cp.titleAlt||_cp.name;
  resolveEpId(sName,sAlt,sEp).then(function(epId){
    var pw=document.getElementById('pwrap');if(!pw)return;
    var pl=document.getElementById('pload');if(pl)pl.remove();
    var ifr=document.createElement('iframe');
    ifr.src=_c+'/'+epId+'/'+sLang;
    ifr.setAttribute('allowfullscreen','');
    ifr.setAttribute('allow','autoplay; fullscreen; picture-in-picture; encrypted-media');
    pw.appendChild(ifr);
  }).catch(function(err){
    var pw=document.getElementById('pwrap');if(!pw)return;
    var pl=document.getElementById('pload');if(pl)pl.remove();
    var isDub=_cp.lang==='dub';
    var userMsg=isDub?'The dub for this episode may not be available yet. Try switching to SUB.':'This episode could not be loaded. Please try again.';
    pw.innerHTML='<div class="perror"><svg width="36" height="36" fill="none" stroke="var(--acc2)" stroke-width="1.5" viewBox="0 0 24 24" style="margin-bottom:4px"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><circle cx="12" cy="16" r=".6" fill="var(--acc2)"/></svg><h4>Could not load episode</h4><p>'+esc(userMsg)+'</p><button class="bp" onclick="retryPlayer()" style="font-size:12px;padding:8px 18px;margin-top:4px">Retry</button></div>';
  });
}
function reloadPlayer(){var wrap=document.getElementById('pwrap');if(!wrap)return;wrap.innerHTML='<div class="pload" id="pload">'+spin()+'</div>';startPlayer();}
window.retryPlayer=function(){var wrap=document.getElementById('pwrap');if(!wrap)return;wrap.innerHTML='<div class="pload" id="pload">'+spin()+'</div>';startPlayer();};

/* ─── COMMUNITY ─── */
function renderCommunity(){
  pbStart();
  var app=document.getElementById('app');
  app.innerHTML='';

  var page=document.createElement('div');page.className='comm-page';
  page.innerHTML=
    /* ── Sidebar ── */
    '<div class="comm-sidebar">'+
      '<div class="comm-sidebar-box">'+
        '<h2 class="comm-title">Community</h2>'+
        '<p class="comm-sub">Share your anime thoughts &mdash; text only, max 150 words. Posts auto-delete after 7 days.</p>'+
        '<div class="comm-sidebar-divider"></div>'+
        '<div class="comm-stat">'+
          '<svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>'+
          '<span>Posts visible to <strong>everyone</strong></span>'+
        '</div>'+
        '<div class="comm-stat">'+
          '<svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>'+
          '<span>Auto-deleted after <strong>7 days</strong></span>'+
        '</div>'+
        '<div class="comm-stat">'+
          '<svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>'+
          '<span>Max <strong>150 words</strong> per post</span>'+
        '</div>'+
        '<div class="comm-sidebar-divider"></div>'+
        /* Inline post form in sidebar */
        '<div class="comm-form-row"><input class="comm-input" id="cs-name" placeholder="Your name" maxlength="40" autocomplete="off"/></div>'+
        '<textarea class="comm-textarea" id="cs-body" placeholder="What\'s on your mind?" rows="4"></textarea>'+
        '<div style="display:flex;align-items:center;justify-content:space-between;margin-top:8px">'+
          '<span class="comm-count" id="cs-count">0 / 150 words</span>'+
        '</div>'+
        '<button class="comm-post-btn" id="cs-post" disabled>Post</button>'+
      '</div>'+
    '</div>'+
    /* ── Feed ── */
    '<div class="comm-feed-wrap">'+
      '<div class="comm-mob-hdr">'+
        '<h2>Community</h2>'+
        '<p>Text only &mdash; max 150 words. Posts delete after 7 days.</p>'+
      '</div>'+
      '<div class="comm-feed-hdr">'+
        '<span class="comm-feed-title">Latest Posts</span>'+
      '</div>'+
      '<div class="comm-feed" id="cfeed"><div class="comm-loader">'+spin()+'</div></div>'+
    '</div>';
  app.appendChild(page);

  /* Floating plus button (mobile) */
  var fab=document.createElement('button');fab.className='comm-fab';fab.title='New Post';
  fab.innerHTML='<svg width="22" height="22" fill="none" stroke="#fff" stroke-width="2.5" viewBox="0 0 24 24"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>';
  document.body.appendChild(fab);
  /* Hide fab on desktop, show on mobile */
  function toggleFab(){fab.style.display=window.innerWidth<=900?'flex':'none';}
  toggleFab();window.addEventListener('resize',toggleFab);

  pbDone();

  /* Helpers */
  function countWords(s){return s.trim()===''?0:s.trim().split(/\s+/).length;}
  function relTime(ts){
    var diff=Math.floor((Date.now()-ts)/1000);
    if(diff<60)return diff+'s ago';
    if(diff<3600)return Math.floor(diff/60)+'m ago';
    if(diff<86400)return Math.floor(diff/3600)+'h ago';
    return Math.floor(diff/86400)+'d ago';
  }
  function avatarLetter(name){return(name||'?')[0].toUpperCase();}
  function makePost(key,data){
    var d=document.createElement('div');d.className='comm-card';d.dataset.key=key;
    d.innerHTML=
      '<div class="comm-card-hdr">'+
        '<div class="comm-avatar">'+esc(avatarLetter(data.name))+'</div>'+
        '<span class="comm-author">'+esc(data.name)+'</span>'+
        '<span class="comm-time">'+relTime(data.ts)+'</span>'+
      '</div>'+
      '<div class="comm-body">'+esc(data.body)+'</div>';
    return d;
  }

  /* Auto-cleanup posts older than 7 days */
  function pruneOld(){
    var cutoff=Date.now()-(7*24*60*60*1000);
    window._fbDb.ref('community').orderByChild('ts').endAt(cutoff).once('value',function(snap){
      snap.forEach(function(child){child.ref.remove();});
    });
  }
  pruneOld();

  /* ── Refreshless real-time feed using child_added ── */
  var feed=document.getElementById('cfeed');
  var _commRef=window._fbDb.ref('community');
  var _postsMap={};   /* key -> DOM node */
  var _loaded=false;

  /* Load last 50 posts in order */
  _commRef.orderByChild('ts').limitToLast(50).once('value',function(snap){
    feed.innerHTML='';
    var posts=[];
    snap.forEach(function(child){posts.push({key:child.key,val:child.val()});});
    posts.reverse();
    if(!posts.length){
      feed.innerHTML='<div class="comm-empty">No posts yet. Be the first!</div>';
    } else {
      posts.forEach(function(p){
        var el=makePost(p.key,p.val);
        _postsMap[p.key]=el;
        feed.appendChild(el);
      });
    }
    _loaded=true;

    /* Now listen for NEW posts added after initial load */
    var latestTs=posts.length?posts[0].val.ts:Date.now();
    _commRef.orderByChild('ts').startAt(latestTs+1).on('child_added',function(snap){
      if(!_loaded)return;
      var key=snap.key,val=snap.val();
      if(_postsMap[key])return; /* already shown */
      /* Remove empty placeholder if present */
      var empty=feed.querySelector('.comm-empty');if(empty)empty.remove();
      var el=makePost(key,val);
      _postsMap[key]=el;
      feed.insertBefore(el,feed.firstChild); /* newest on top */
    });

    /* Listen for removed posts (7-day cleanup) */
    _commRef.on('child_removed',function(snap){
      var el=_postsMap[snap.key];
      if(el&&el.parentNode){el.parentNode.removeChild(el);}
      delete _postsMap[snap.key];
      if(!feed.children.length){
        feed.innerHTML='<div class="comm-empty">No posts yet. Be the first!</div>';
      }
    });
  });

  /* ── Post submit logic (shared by sidebar form and modal) ── */
  function doPost(name,body,onSuccess,onFail){
    if(!name||!body||countWords(body)>150)return;
    window._fbDb.ref('community').push({name:name,body:body,ts:Date.now()})
      .then(function(){
        try{localStorage.setItem('comm_name',name);}catch(e){}
        toast('Posted!');
        if(onSuccess)onSuccess();
      })
      .catch(function(e){toast('Failed: '+e.message);if(onFail)onFail();});
  }

  /* ── Sidebar form (desktop) ── */
  var sNameEl=document.getElementById('cs-name');
  var sBodyEl=document.getElementById('cs-body');
  var sCountEl=document.getElementById('cs-count');
  var sPostBtn=document.getElementById('cs-post');
  if(sNameEl){
    try{var sn=localStorage.getItem('comm_name');if(sn)sNameEl.value=sn;}catch(e){}
    function sValidate(){
      var wc=countWords(sBodyEl.value);
      sCountEl.textContent=wc+' / 150 words';
      sCountEl.className='comm-count'+(wc>150?' err':wc>120?' warn':'');
      sPostBtn.disabled=(wc===0||wc>150||sNameEl.value.trim().length===0);
    }
    sBodyEl.addEventListener('input',sValidate);
    sNameEl.addEventListener('input',sValidate);
    sPostBtn.addEventListener('click',function(){
      sPostBtn.disabled=true;sPostBtn.textContent='Posting...';
      doPost(sNameEl.value.trim(),sBodyEl.value.trim(),function(){
        sBodyEl.value='';sCountEl.textContent='0 / 150 words';sCountEl.className='comm-count';
        sPostBtn.textContent='Post';sPostBtn.disabled=true;
      },function(){sPostBtn.disabled=false;sPostBtn.textContent='Post';});
    });
  }

  /* ── Modal (mobile fab) ── */
  function openModal(){
    var bg=document.createElement('div');bg.className='comm-modal-bg';
    bg.innerHTML=
      '<div class="comm-modal">'+
        '<div class="comm-modal-hdr">'+
          '<span class="comm-modal-title">New Post</span>'+
          '<button class="comm-modal-close" id="cm-close">'+
            '<svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2.2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>'+
          '</button>'+
        '</div>'+
        '<div class="comm-form-row" style="margin-bottom:10px">'+
          '<input class="comm-input" id="cm-name" placeholder="Your name" maxlength="40" autocomplete="off"/>'+
        '</div>'+
        '<textarea class="comm-textarea" id="cm-body" placeholder="What\'s on your mind? (max 150 words)" rows="5"></textarea>'+
        '<div class="comm-form-footer" style="margin-top:10px">'+
          '<span class="comm-count" id="cm-count">0 / 150 words</span>'+
          '<button class="comm-post-btn" id="cm-post" disabled style="width:auto">Post</button>'+
        '</div>'+
      '</div>';
    document.body.appendChild(bg);
    var nameEl=document.getElementById('cm-name');
    var bodyEl=document.getElementById('cm-body');
    var countEl=document.getElementById('cm-count');
    var postBtn=document.getElementById('cm-post');
    try{var sn2=localStorage.getItem('comm_name');if(sn2)nameEl.value=sn2;}catch(e){}
    function mValidate(){
      var wc=countWords(bodyEl.value);
      countEl.textContent=wc+' / 150 words';
      countEl.className='comm-count'+(wc>150?' err':wc>120?' warn':'');
      postBtn.disabled=(wc===0||wc>150||nameEl.value.trim().length===0);
    }
    bodyEl.addEventListener('input',mValidate);
    nameEl.addEventListener('input',mValidate);
    nameEl.focus();
    function closeModal(){if(bg.parentNode)bg.parentNode.removeChild(bg);}
    document.getElementById('cm-close').addEventListener('click',closeModal);
    bg.addEventListener('click',function(e){if(e.target===bg)closeModal();});
    postBtn.addEventListener('click',function(){
      postBtn.disabled=true;postBtn.textContent='Posting...';
      doPost(nameEl.value.trim(),bodyEl.value.trim(),function(){closeModal();},
        function(){postBtn.disabled=false;postBtn.textContent='Post';});
    });
  }
  fab.addEventListener('click',openModal);

  /* Cleanup on navigate away */
  function cleanup(){
    fab.remove();
    window.removeEventListener('resize',toggleFab);
    _commRef.off();
    _loaded=false;
  }
  var _origGo=window.go;
  window.go=function(){cleanup();window.go=_origGo;_origGo.apply(this,arguments);};
}

/* ─── Search ─── */
function doSearch(q){q=(q||'').trim();if(!q&&!hasFilters())return;document.getElementById('si').value=q||'';go('search',{q:q});}
var _sb=document.getElementById('sb'),_si=document.getElementById('si');
if(_sb)_sb.addEventListener('click',function(){doSearch(_si?_si.value:'');});
if(_si)_si.addEventListener('keydown',function(e){if(e.key==='Enter')doSearch(this.value);});

/* ─── Nav ─── */
document.querySelectorAll('.hn[data-v]').forEach(function(b){b.addEventListener('click',function(){go(this.dataset.v);});});
var _logo=document.getElementById('logo');if(_logo)_logo.addEventListener('click',function(){go('home');});

/* ─── Back to top ─── */
var btt=document.getElementById('btt');
if(btt){
  window.addEventListener('scroll',function(){btt.style.display=window.scrollY>500?'flex':'none';},{passive:true});
  btt.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'});});
}

/* ─── Boot ─── */
/* Boot - dismiss loader immediately on DOMContentLoaded, fallback to load */
function bootApp(){
  var ldr=document.getElementById('loader');
  if(ldr)ldr.classList.add('off');
  S=fromURL();
  if(S.view==='landing'){var _h=document.getElementById('hdr');if(_h)_h.classList.add('hidden');var _a=document.getElementById('app');if(_a)_a.style.paddingTop='0';}
  try{history.replaceState(S,'',location.href);}catch(e){}
  syncNav();
  render(false);
}
if(document.readyState==='loading'){
  document.addEventListener('DOMContentLoaded',function(){bootApp();});
} else {
  bootApp();
}

})();
